window.HADITH_CACHE["malik_3"] = {"1501":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِأَنَّهُ كَانَ يَقُولُ فِي هَذِهِ الْآيَةِ{ لَهُمْ الْبُشْرَى فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }قَالَ هِيَ الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الرَّجُلُ الصَّالِحُ أَوْ تُرَى لَهُ","id":"Telah menceritakan kepadaku dari Malik dari [Hisyam bin 'Urwah] dari [Bapaknya] menafsirkan tentang ayat: '(Bagi mereka kabar gembira di kehidupan dunia maupun akhirat) ' (Qs. Yunus: 64) \"Yaitu mimpi baik yang dilihat orang yang shalih atau diperlihatkan padanya.\""},"1502":{"ar":"حَدَّثَنِي عَنْ مَالِك عَنْ مُوسَى بْنِ مَيْسَرَةَ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَعِبَ بِالنَّرْدِ فَقَدْ عَصَى اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepadaku dari Malik dari [Musa bin Maisarah] dari [Sa'id bin Abu Hind] dari [Abu Musa Al Asy'ari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bermain dadu, maka dia telah bermaksiat kepada Allah dan RasulNya.\""},"1503":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ عَلْقَمَةَ بْنِ أَبِي عَلْقَمَةَ عَنْ أُمِّهِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ بَلَغَهَاأَنَّ أَهْلَ بَيْتٍ فِي دَارِهَا كَانُوا سُكَّانًا فِيهَا وَعِنْدَهُمْ نَرْدٌ فَأَرْسَلَتْ إِلَيْهِمْ لَئِنْ لَمْ تُخْرِجُوهَا لَأُخْرِجَنَّكُمْ مِنْ دَارِي وَأَنْكَرَتْ ذَلِكَ عَلَيْهِمْ","id":"Telah menceritakan kepadaku dari Malik dari ['Alqamah bin Abu 'Alqamah] dari [Ibunya] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, telah sampai kabar kepadanya bahwa ada penghuni sebuah rumah di kampungnya memiliki dadu. Maka 'Aisyah mengirim utusan kepada mereka untuk menyampaikan pesan kepada mereka, \"Jika kalian tidak mengeluarkannya, niscaya aku akan mengusir kalian dari kampungku'. Dan 'Aisyah pun mengingkari mereka.\""},"1504":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ كَانَ إِذَا وَجَدَ أَحَدًا مِنْ أَهْلِهِ يَلْعَبُ بِالنَّرْدِ ضَرَبَهُ وَكَسَرَهَاقَالَ يَحْيَى و سَمِعْت قَوْله تَعَالَى يَقُولُ لَا خَيْرَ فِي الشَّطْرَنْجِ وَكَرِهَهَا وَسَمِعْتُهُ يَكْرَهُ اللَّعِبَ بِهَا وَبِغَيْرِهَا مِنْ الْبَاطِلِ وَيَتْلُو هَذِهِ الْآيَةَ{ فَمَاذَا بَعْدَ الْحَقِّ إِلَّا الضَّلَالُ }","id":"Telah menceritakan kepadaku dari Malik dari [Nafi'] dari [Abdullah bin Umar] bahwa jika dia mendapati salah seorang keluarganya bermain dadu, maka dia memukulnya dan memecahkan dadu tersebut. Yahya berkata; \"Aku mendengar Malik berkata; 'Tidak ada kebaikan dalam dadu', dia membencinya, dan aku juga mendengar bahwa dia membenci permainan dadu atau yang lainnya yang termasuk hal yang batil, lalu dia membaca ayat ini: '(Maka tidak ada sesudah kebenaran itu, melainkan kesesatan) ' (Qs. Yunus; 32) "},"1505":{"ar":"حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسَلِّمُ الرَّاكِبُ عَلَى الْمَاشِي وَإِذَا سَلَّمَ مِنْ الْقَوْمِ وَاحِدٌ أَجْزَأَ عَنْهُمْ","id":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang berkendaraan memberi salam kepada yang berjalan. Jika salah seorang dari suatu kaum memberi salam maka itu cukup bagi mereka.\""},"1506":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ أَنَّهُ قَالَ كُنْتُ جَالِسًا عِنْدَ عَبْدِ اللَّهِ بْنِ عَبَّاسٍفَدَخَلَ عَلَيْهِ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ فَقَالَ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ ثُمَّ زَادَ شَيْئًا مَعَ ذَلِكَ أَيْضًا قَالَ ابْنُ عَبَّاسٍ وَهُوَ يَوْمَئِذٍ قَدْ ذَهَبَ بَصَرُهُ مَنْ هَذَا قَالُوا هَذَا الْيَمَانِي الَّذِي يَغْشَاكَ فَعَرَّفُوهُ إِيَّاهُ قَالَ فَقَالَ ابْنُ عَبَّاسٍ إِنَّ السَّلَامَ انْتَهَى إِلَى الْبَرَكَةِ","id":"Telah menceritakan kepadaku dari Malik dari [Wahab bin Kaisan] dari [Muhammad bin 'Amru bin Atha] berkata; \"Aku duduk di samping Abdullah bin 'Abbas, lalu seorang penduduk Yaman menemuinya dan mengucapkan; 'ASSALAAMU 'ALAIKUM WARAHMATULLAHI WA BARAKAATUHU (semoga keselamatan dan rahmat Allah serta barakah-Nya tercurah kepada kalian), ' kemudian dia menambahinya dengan sesuatu.\" Ibnu 'Abbas yang ketika itu sudah buta matanya bertanya; \"Siapakah orang itu?\" Mereka menjawab; \"Ini adalah orang Yaman yang hendak menemuimu.\" Kemudian mereka mengenalkannya. Muhammad bin 'Amru berkata: \" [Ibnu 'Abbas] berkata 'Salam itu terhenti pada kata AL BARAKAH.\""},"1507":{"ar":"حَدَّثَنِي عَنْ مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْيَهُودَ إِذَا سَلَّمَ عَلَيْكُمْ أَحَدُهُمْ فَإِنَّمَا يَقُولُ السَّامُ عَلَيْكُمْ فَقُلْ عَلَيْكَقَالَ يَحْيَى و سُئِلَ مَالِك عَمَّنْ سَلَّمَ عَلَى الْيَهُودِيِّ أَوْ النَّصْرَانِيِّ هَلْ يَسْتَقِيلُهُ ذَلِكَ فَقَالَ لَا","id":"Telah menceritakan kepadaku dari Malik dari [Abdullah bin Dinar] dari [Abdullah bin Umar] berkata Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang Yahudi mengucapkan salam kepada kalian, hanyasanya mereka mengucapkan; ASSAAMU 'ALAIKUM (kebinasaan atas kalian) maka jawablah; 'ALAIKA (juga atas kalian) .\" Yahya berkata; \"Malik ditanya tentang seseorang yang memberi salam kepada orang Yahudi atau Nasrani, apakah dia harus menarik ucapannya? dia menjawab, \"Tidak perlu.\""},"1508":{"ar":"حَدَّثَنِي عَنْ مَالِك عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ جَالِسٌ فِي الْمَسْجِدِ وَالنَّاسُ مَعَهُ إِذْ أَقْبَلَ نَفَرٌ ثَلَاثَةٌ فَأَقْبَلَ اثْنَانِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَهَبَ وَاحِدٌ فَلَمَّا وَقَفَا عَلَى مَجْلِسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَّمَا فَأَمَّا أَحَدُهُمَا فَرَأَى فُرْجَةً فِي الْحَلْقَةِ فَجَلَسَ فِيهَا وَأَمَّا الْآخَرُ فَجَلَسَ خَلْفَهُمْ وَأَمَّا الثَّالِثُ فَأَدْبَرَ ذَاهِبًا فَلَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ عَنْ النَّفَرِ الثَّلَاثَةِ أَمَّا أَحَدُهُمْ فَأَوَى إِلَى اللَّهِ فَآوَاهُ اللَّهُ وَأَمَّا الْآخَرُ فَاسْتَحْيَا فَاسْتَحْيَا اللَّهُ مِنْهُ وَأَمَّا الْآخَرُ فَأَعْرَضَ فَأَعْرَضَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepadaku dari Malik dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Abu Murrah] mantan budak 'Aqil bin Abu Thalib, dari [Abu Waqid Al Laitsi] bahwa ketika Rasulullah shallallahu 'alaihi wasallam duduk di masjid bersama orang-orang. Datanglah tiga orang, dua orang menuju ke Rasulullah shallallahu 'alaihi wasallam dan yang satu keluar. Ketika mereka berdua berdiri di majlis Rasulullah shallallahu 'alaihi wasallam, mereka mengucapkan salam. Salah seorang dari mereka melihat ada tempat yang kosong di kumpulan orang lalu dia mendudukinya. Orang kedua duduk di belakang mereka, sedangkan yang ketiga mundur dan pergi. Setelah selesai Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku kabarkan kepada kalian tentang tiga orang tadi; yang pertama dia telah berlindung kepada Allah, maka Allah pun melindunginya. Orang yang kedua, dia merasa malu, maka Allah pun malu darinya, sedangkan yang ketiga, dia berpaling maka Allah pun berpaling darinya.\""},"1509":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ سَمِعَ عُمَرَ بْنَ الْخَطَّابِوَسَلَّمَ عَلَيْهِ رَجُلٌ فَرَدَّ عَلَيْهِ السَّلَامَ ثُمَّ سَأَلَ عُمَرُ الرَّجُلَ كَيْفَ أَنْتَ فَقَالَ أَحْمَدُ إِلَيْكَ اللَّهَ فَقَالَ عُمَرُ ذَلِكَ الَّذِي أَرَدْتُ مِنْكَ","id":"Telah menceritakan kepadaku dari Malik dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwa dia telah mendengar seorang laki-laki memberi salam kepada Umar bin Khattab, lalu ia menjawabnya. Kemudian Umar bertanya kepada lelaki tadi; \"Bagaimana keadaanmu?\" laki-laki itu menjawab; \"Aku memuji Allah untuk (keberkahan) mu.\" Lalu [Umar] berkata; \"Itu yang aku mau darimu.\""},"1510":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّ الطُّفَيْلَ بْنَ أُبَيِّ بْنِ كَعْبٍ أَخْبَرَهُأَنَّهُ كَانَ يَأْتِي عَبْدَ اللَّهِ بْنَ عُمَرَ فَيَغْدُو مَعَهُ إِلَى السُّوقِ قَالَ فَإِذَا غَدَوْنَا إِلَى السُّوقِ لَمْ يَمُرَّ عَبْدُ اللَّهِ بْنُ عُمَرَ عَلَى سَقَاطٍ وَلَا صَاحِبِ بِيعَةٍ وَلَا مِسْكِينٍ وَلَا أَحَدٍ إِلَّا سَلَّمَ عَلَيْهِ قَالَ الطُّفَيْلُ فَجِئْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَوْمًا فَاسْتَتْبَعَنِي إِلَى السُّوقِ فَقُلْتُ لَهُ وَمَا تَصْنَعُ فِي السُّوقِ وَأَنْتَ لَا تَقِفُ عَلَى الْبَيِّعِ وَلَا تَسْأَلُ عَنْ السِّلَعِ وَلَا تَسُومُ بِهَا وَلَا تَجْلِسُ فِي مَجَالِسِ السُّوقِ قَالَ وَأَقُولُ اجْلِسْ بِنَا هَاهُنَا نَتَحَدَّثُ قَالَ فَقَالَ لِي عَبْدُ اللَّهِ بْنُ عُمَرَ يَا أَبَا بَطْنٍ وَكَانَ الطُّفَيْلُ ذَا بَطْنٍ إِنَّمَا نَغْدُو مِنْ أَجْلِ السَّلَامِ نُسَلِّمُ عَلَى مَنْ لَقِيَنَا","id":"Telah menceritakan kepadaku dari Malik dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa [Thufail bin Ubay bin Ka'b] mengabarkan kepadanya, bahwa dia pernah mendatangi [Abdullah bin Umar] lalu dia pergi ke pasar bersamanya. Thufail bin Ubay berkata; \"Ketika kami pergi ke pasar, tidaklah Abdullah bin Umar melewati rakyat jelata, atau para penjual atau orang miskin atau siapa pun kecuali dia memberinya salam.\" Thufail berkata; \"Pada suatu hari aku menemui Abdullah bin Umar, lalu dia mengajakku pergi ke pasar, aku bertanya kepadanya, \"Apa yang engkau kerjakan di pasar padahal engkau tidak berhenti ke sebuah toko, atau menanyakan barang, tidak menawar sesuatu, atau duduk di tempat penjualan?\" dia menjawab, \"Aku katakan, \"Duduklah di sini kita bicarakan sesuatu.\" lalu Abdullah bin Umar berkata kepadaku, \"Wahai Abu Bathn (perut besar)! -karena ketika itu Thufail perutnya besar-, kita pergi ke pasar hanya untuk mengucapkan salam kepada siapapun yang kita temui'.\""},"1511":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّ رَجُلًا سَلَّمَ عَلَى عَبْدِ اللَّهِ بْنِ عُمَرَفَقَالَ السَّلَامُ عَلَيْكَ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ وَالْغَادِيَاتُ وَالرَّائِحَاتُ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ عُمَرَ وَعَلَيْكَ أَلْفًا ثُمَّ كَأَنَّهُ كَرِهَ ذَلِكَ","id":"Telah menceritakan kepadaku dari Malik dari [Yahya bin Sa'id] berkata, \"Seorang laki-laki mengucapkan salam kepada Abdullah bin Umar, dia katakan, \"ASSAALAMU 'ALAIKA WA RAHMATULLAH WA BARAKAATUHU WALGHAADIYAATu WARRAA`IHAT (Semoga keselamatan, rahmat dan barakah Allah tercurah kepadamu, dan orang-orang yang pada pagi hari dan sorenya) .\" [Abdullah bin Umar] kemudian menjawabnya; \"WA'ALAIKA ALFAN (dan atas kamu seribu kali), \" seakan-akan dia membenci hal itu."},"1512":{"ar":"حَدَّثَنِي مَالِك عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أَسْتَأْذِنُ عَلَى أُمِّي فَقَالَ نَعَمْ قَالَ الرَّجُلُ إِنِّي مَعَهَا فِي الْبَيْتِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَأْذِنْ عَلَيْهَا فَقَالَ الرَّجُلُ إِنِّي خَادِمُهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَأْذِنْ عَلَيْهَا أَتُحِبُّ أَنْ تَرَاهَا عُرْيَانَةً قَالَ لَا قَالَ فَاسْتَأْذِنْ عَلَيْهَا","id":"Telah menceritakan kepadaku Malik dari [Shafwan bin Sulaim] dari [Atha bin Yasar] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya oleh seorang laki-laki, \"Wahai Rasulullah, haruskah aku minta izin kepada ibuku (jika masuk ke kamarnya)?\" beliau menjawab: \"Ya.\" Laki-laki itu bertanya lagi, \"Aku tinggal bersamanya dalam satu rumah?\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mintalah izin kepadanya.\" Laki-laki itu bertanya lagi, \"Aku juga sebagai pelayannya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Mintalah izin kepadanya, apakah engkau mau jika mendapatinya sedang telanjang! \" Dia menjawab; \"Tidak.\" Beliau bersabda: \"Maka mintalah izin! \""},"1513":{"ar":"و حَدَّثَنِي مَالِك عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ غَيْرِ وَاحِدٍ مِنْ عُلَمَائِهِمْ أَنَّ أَبَا مُوسَى الْأَشْعَرِيَّجَاءَ يَسْتَأْذِنُ عَلَى عُمَرَ بْنِ الْخَطَّابِ فَاسْتَأْذَنَ ثَلَاثًا ثُمَّ رَجَعَ فَأَرْسَلَ عُمَرُ بْنُ الْخَطَّابِ فِي أَثَرِهِ فَقَالَ مَا لَكَ لَمْ تَدْخُلْ فَقَالَ أَبُو مُوسَى سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْاسْتِئْذَانُ ثَلَاثٌ فَإِنْ أُذِنَ لَكَ فَادْخُلْ وَإِلَّا فَارْجِعْ فَقَالَ عُمَرُ وَمَنْ يَعْلَمُ هَذَا لَئِنْ لَمْ تَأْتِنِي بِمَنْ يَعْلَمُ ذَلِكَ لَأَفْعَلَنَّ بِكَ كَذَا وَكَذَا فَخَرَجَ أَبُو مُوسَى حَتَّى جَاءَ مَجْلِسًا فِي الْمَسْجِدِ يُقَالُ لَهُ مَجْلِسُ الْأَنْصَارِ فَقَالَ إِنِّي أَخْبَرْتُ عُمَرَ بْنَ الْخَطَّابِ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْاسْتِئْذَانُ ثَلَاثٌ فَإِنْ أُذِنَ لَكَ فَادْخُلْ وَإِلَّا فَارْجِعْ فَقَالَ لَئِنْ لَمْ تَأْتِنِي بِمَنْ يَعْلَمُ هَذَا لَأَفْعَلَنَّ بِكَ كَذَا وَكَذَا فَإِنْ كَانَ سَمِعَ ذَلِكَ أَحَدٌ مِنْكُمْ فَلْيَقُمْ مَعِي فَقَالُوا لِأَبِي سَعِيدٍ الْخُدْرِيِّ قُمْ مَعَهُ وَكَانَ أَبُو سَعِيدٍ أَصْغَرَهُمْ فَقَامَ مَعَهُ فَأَخْبَرَ بِذَلِكَ عُمَرَ بْنَ الْخَطَّابِ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ لِأَبِي مُوسَى أَمَا إِنِّي لَمْ أَتَّهِمْكَ وَلَكِنْ خَشِيتُ أَنْ يَتَقَوَّلَ النَّاسُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku Malik dari [Rabi'ah bin Abu Abdurrahman] dari [lebih dari satu ulama mereka] bahwa [Abu Musa Al Asy'ari] datang meminta izin kepada Umar bin Khattab, lalu ia mengucapkan salam hingga tiga kali, setelah itu ia kembali pulang. Umar bin Khattab mengutus seseorang untuk mengejarnya. Umar bertanya; \"Kenapa kamu tidak masuk?\" Abu Musa Al Asy'ari menjawab; \"Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Minta izin itu tiga kali. Jika kamu diizinkan, masuklah. Jika tidak, maka pulanglah'! \" Lalu Umar bin Khattab berkata; \"Selain engkau siapa yang tahu tentang hadits ini? Jika engkau tidak mendatangkannya kepadaku, maka aku akan melakukan ini dan itu terhadapmu.\" Kemudian Abu Musa keluar hingga mendapatkan suatu majlis di dalam masjid yang disebut majlis Anshar. Dia berkata; \"Aku telah mengabari Umar bin Khattab bahwa aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Minta izin itu tiga kali, jika engkau diizinkan maka masuklah, namun jika tidak maka pulanglah.' lalu Umar berkata; 'Kalau engkau tidak mendatangkan kepadaku siapa saja yang mengetahui hal ini, maka aku akan melakukan begini dan begitu. Maka jika salah seorang di antara kalian pernah mendengarnya, ikutlah denganku.\" Orang-orang lalu berkata kepada [Abu Sa'id Al Khudri]; \"Ikutlah bersamanya! \" ketika itu Abu Sa'id Al Khudri adalah orang yang termuda di antara mereka, maka ia pun pergi bersama Abu Musa dan memberi kesaksian kepada Umar bin Khattab. Kemudian Umar bin Khattab berkata kepada Abu Musa; \"Aku tidak meragukanmu, hanya saja aku khawatir jika manusia membuat-buat ucapan (yang dinisbatkan) atas Rasulullah shallallahu 'alaihi wasallam.\""},"1514":{"ar":"حَدَّثَنِي مَالِك عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ عَطَسَ فَشَمِّتْهُ ثُمَّ إِنْ عَطَسَ فَشَمِّتْهُ ثُمَّ إِنْ عَطَسَ فَشَمِّتْهُ ثُمَّ إِنْ عَطَسَ فَقُلْ إِنَّكَ مَضْنُوكٌقَالَ عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ لَا أَدْرِي أَبَعْدَ الثَّالِثَةِ أَوْ الرَّابِعَةِ","id":"Telah menceritakan kepadaku Malik dari [Abdullah bin Abu Bakar] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika ada yang bersin, maka bertasymitlah. Jika bersin lagi maka bertasymitlah, lalu jika bersin lagi maka bertasymitlah. Jika masih bersin maka katakanlah; 'Kamu sedang sakit pilek'.\" Abdullah bin Abu Bakar berkata; \"Aku tidak tahu apakah (mengatakannya) setelah yang ketiga atau keempat.\" "},"1515":{"ar":"و حَدَّثَنِي مَالِك عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَكَانَ إِذَا عَطَسَ فَقِيلَ لَهُ يَرْحَمُكَ اللَّهُ قَالَ يَرْحَمُنَا اللَّهُ وَإِيَّاكُمْ وَيَغْفِرُ لَنَا وَلَكُمْ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] berkata, \"Ketika [Abdullah bin Umar] bersin, lalu ada yang mendoakan kepadanya; \"YARHAMUKALLAH (Semoga Allah merahmatimu) \" Maka ia membalas; \"YARHAMUNA ALLAHU WA IYYAKUM WA YAGHFIRU LANA WA LAKUM (Semoga Allah merahmatiku dan kalian dan mengampuni dosaku dan kalian) .\""},"1516":{"ar":"حَدَّثَنِي مَالِك عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّ رَافِعَ بْنَ إِسْحَقَ مَوْلَى الشِّفَاءِ أَخْبَرَهُ قَالَدَخَلْتُ أَنَا وَعَبْدُ اللَّهِ بْنُ أَبِي طَلْحَةَ عَلَى أَبِي سَعِيدٍ الْخُدْرِيِّ نَعُودُهُ فَقَالَ لَنَا أَبُو سَعِيدٍ أَخْبَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْمَلَائِكَةَ لَا تَدْخُلُ بَيْتًا فِيهِ تَمَاثِيلُ أَوْ تَصَاوِيرُشَكَّ إِسْحَقُ لَا يَدْرِي أَيَّتَهُمَا قَالَ أَبُو سَعِيدٍ","id":"Telah menceritakan kepadaku Malik dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa [Rafi' bin Ishaq] mantan budak Asy Syifa', mengabarkan kepadanya, ia berkata, \"Aku masuk ke rumah Abu Sa'id Al Khudri bersama Abdullah bin Abu Thalhah untuk menjenguknya.\" Maka [Abu Sa'id] berkata kepada kami; \"Rasulullah shallallahu 'alaihi wasallam mengabarkan kepadaku bahwa para Malaikat tidak akan masuk rumah yang ada patung, atau gambar di dalamnya.\" Ishaq ragu yang mana di antara keduanya yang dikatakan Abu Sa'id.\""},"1517":{"ar":"و حَدَّثَنِي مَالِك عَنْ أَبِي النَّضْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّهُ دَخَلَ عَلَى أَبِي طَلْحَةَ الْأَنْصَارِيِّيَعُودُهُ قَالَ فَوَجَدَ عِنْدَهُ سَهْلَ بْنَ حُنَيْفٍ فَدَعَا أَبُو طَلْحَةَ إِنْسَانًا فَنَزَعَ نَمَطًا مِنْ تَحْتِهِ فَقَالَ لَهُ سَهْلُ بْنُ حُنَيْفٍ لِمَ تَنْزِعُهُ قَالَ لِأَنَّ فِيهِ تَصَاوِيرَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا مَا قَدْ عَلِمْتَ فَقَالَ سَهْلٌ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مَا كَانَ رَقْمًا فِي ثَوْبٍ قَالَ بَلَى وَلَكِنَّهُ أَطْيَبُ لِنَفْسِي","id":"Telah menceritakan kepadaku Malik dari [Abu Nadlr] dari ['Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] bahwa dia hendak menemui [Abu Thalhah Al Anshari] untuk menjenguknya. Abu An Nadlr berkata; \"Kemudian dia mendapati [Sahl bin Hunaif] sudah ada di sampingnya. Abu Thalhah lalu memanggil seseorang untuk melepas tikar yang ada di bawahnya. Sahl bin Hunaif bertanya; \"Kenapa engkau menariknya?\" dia menjawab; \"Karena ada gambar di dalamnya, padahal Rasulullah shallallahu 'alaihi wasallam telah bersabda sebagaimana yang engkau tahu.\" Lalu Sahl berkata: \"Bukankah Rasulullah shallallahu 'alaihi wasallam bersabda kecuali yang tertulis dalam kain.\" Dia berkata: \"Benar, tapi ini lebih menenangkan jiwaku.\""},"1518":{"ar":"و حَدَّثَنِي مَالِك عَنْ نَافِعٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا اشْتَرَتْ نُمْرُقَةً فِيهَا تَصَاوِيرُ فَلَمَّا رَآهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ عَلَى الْبَابِ فَلَمْ يَدْخُلْ فَعَرَفَتْ فِي وَجْهِهِ الْكَرَاهِيَةَ وَقَالَتْ يَا رَسُولَ اللَّهِ أَتُوبُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ فَمَاذَا أَذْنَبْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا بَالُ هَذِهِ النُّمْرُقَةِ قَالَتْ اشْتَرَيْتُهَا لَكَ تَقْعُدُ عَلَيْهَا وَتَوَسَّدُهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ يُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ ثُمَّ قَالَ إِنَّ الْبَيْتَ الَّذِي فِيهِ الصُّوَرُ لَا تَدْخُلُهُ الْمَلَائِكَةُ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] dari [Al Qasim bin Muhammad] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwasanya ia telah membeli numruqah yang ada gambarnya. Ketika Rasulullah shallallahu 'alaihi wasallam melihatnya, beliau berdiri di depan pintu dan tidak masuk ke dalam rumah. Aisyah melihat pada wajah beliau ada rona kebencian, maka dia bertanya; \"Wahai Rasulullah, aku bertaubat kepada Allah dan Rasul-Nya, dosa apa yang telah aku perbuat?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada apa dengan bantal ini?\" Dia menjawab; \"Aku telah membelinya agar anda duduk dengannya atau anda jadikan sebagai bantal.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang menggambar gambar ini akan disiksa pada Hari Kiamat. Dikatakan kepada mereka; 'Hidupkan yang telah kalian buat, ' kemudian beliau bersabda: \"Sesungguhnya malaikat tidak akan masuk ke dalam rumah yang ada gambarnya.\" "},"1519":{"ar":"حَدَّثَنِي مَالِك عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ أَنَّهُ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ مَيْمُونَةَ بِنْتِ الْحَارِثِ فَإِذَا ضِبَابٌ فِيهَا بَيْضٌ وَمَعَهُ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ وَخَالِدُ بْنُ الْوَلِيدِ فَقَالَ مِنْ أَيْنَ لَكُمْ هَذَا فَقَالَتْ أَهْدَتْهُ لِي أُخْتِي هُزَيْلَةُ بِنْتُ الْحَارِثِ فَقَالَ لِعَبْدِ اللَّهِ بْنِ عَبَّاسٍ وَخَالِدِ بْنِ الْوَلِيدِ كُلَا فَقَالَا أَوَلَا تَأْكُلُ أَنْتَ يَا رَسُولَ اللَّهِ فَقَالَ إِنِّي تَحْضُرُنِي مِنْ اللَّهِ حَاضِرَةٌ قَالَتْ مَيْمُونَةُ أَنَسْقِيكَ يَا رَسُولَ اللَّهِ مِنْ لَبَنٍ عِنْدَنَا فَقَالَ نَعَمْ فَلَمَّا شَرِبَ قَالَ مِنْ أَيْنَ لَكُمْ هَذَا فَقَالَتْ أَهْدَتْهُ لِي أُخْتِي هُزَيْلَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتِكِ جَارِيَتَكِ الَّتِي كُنْتِ اسْتَأْمَرْتِينِي فِي عِتْقِهَا أَعْطِيهَا أُخْتَكِ وَصِلِي بِهَا رَحِمَكِ تَرْعَى عَلَيْهَا فَإِنَّهُ خَيْرٌ لَكِ","id":"Telah menceritakan kepadaku Malik dari [Abdurrahman bin Abdullah bin Abdurrahman bin Abu Sha'sha'ah] dari [Sulaiman bin Yasar] berkata \"Rasulullah shallallahu 'alaihi wasallam memasuki rumah Maimunah binti Al Haris, ternyata di dalamnya ada beberapa biawak dengan telurnya. Beliau saat itu bersama Abdullah bin Abbas dan Khalid bin Walid. Beliau bertanya: \"Dari mana ini?\" Maimunah menjawab, \"Saudariku, Hudzailah binti Al Harits menghadiahkannya kepadaku.\" Beliau berkata kepada Abdullah bin Abbas dan Khalid bin Walid: \"Kalian berdua, makanlah.\" Mereka bertanya; \"Kenapa anda tidak memakannya, Wahai Rasulullah? ' Beliau menjawab: \"Sesungguhnya telah hadir hidangan dari Allah.\" Maimunah bertanya; \"Apakah anda mau kami hidangkan susu?\" Beliau menjawab: \"Ya.\" Dan ketika beliau akan meminum susu tersebut beliau bertanya: \"Dari mana ini?\" Maimunah menjawab; \"Saudariku, Hudzailah menghadiahkan kepadaku.\" Rasulullah shallallahu 'alaihi wasallam bersabda: 'Apa pendapatmu tentang budak wanitamu yang engkau pernah minta agar aku membebaskannya? Berikan (kembalikan) kepada saudarimu dan sambunglah silaturrahim agar dia yang merawatnya karena itu lebih baik untukmu'.\""},"1520":{"ar":"و حَدَّثَنِي مَالِك عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ خَالِدِ بْنِ الْوَلِيدِ بْنِ الْمُغِيرَةِأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُتِيَ بِضَبٍّ مَحْنُوذٍ فَأَهْوَى إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ فَقَالَ بَعْضُ النِّسْوَةِ اللَّاتِي فِي بَيْتِ مَيْمُونَةَ أَخْبِرُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا يُرِيدُ أَنْ يَأْكُلَ مِنْهُ فَقِيلَ هُوَ ضَبٌّ يَا رَسُولَ اللَّهِ فَرَفَعَ يَدَهُ فَقُلْتُ أَحَرَامٌ هُوَ يَا رَسُولَ اللَّهِ فَقَالَ لَا وَلَكِنَّهُ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ","id":"Telah menceritakan kepadaku Malik dari [Ibnu Syihab] dari [Abu Umamah bin Sahl bin Hunaif] dari [Abdullah bin Abbas] dari [Khalid bin Walid bin Al Mughirah] bahwa dia bersama Rasulullah shallallahu 'alaihi wasallam memasuki rumah Maimunah, isteri Nabi shallallahu 'alaihi wasallam. Kemudian dihidangkan daging biawak yang telah dipanggang, lalu Rasulullah shallallahu 'alaihi wasallam mengulurkan tangannya untuk mengambilnya, tetapi para wanita yang ada di sana berkata; \"Beritahu Rasulullah shallallahu 'alaihi wasallam tentang apa yang hendak beliau makan! \" Maka dikatakan kepada beliau; \"Itu adalah daging biawak, Wahai Rasulullah.\" Maka beliau pun mengangkat kembali tangannya. Khalid bin Walid bertanya; \"Apakah itu haram, Wahai Rasulullah?\" beliau menjawab: \"Tidak, hanya saja daging ini tidak ada di daerahku, maka aku merasa jijik.\" Khalid berkata; \"Aku lalu memotong dan memakannya, sementara Rasulullah shallallahu 'alaihi wasallam melihat.\""},"1521":{"ar":"و حَدَّثَنِي مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَجُلًا نَادَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا تَرَى فِي الضَّبِّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَسْتُ بِآكِلِهِ وَلَا بِمُحَرِّمِهِ","id":"Telah menceritakan kepadaku Malik dari [Abdullah bin Dinar] dari [Abdullah bin Umar] bahwa ada seorang lelaki memanggil Rasulullah shallallahu 'alaihi wasallam; \"Wahai Rasulullah apa pendapat anda tentang daging biawak?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Aku tidak memakannya dan tidak mengharamkannya.\""},"1522":{"ar":"حَدَّثَنِي مَالِك عَنْ يَزِيدَ بْنِ خُصَيْفَةَ أَنَّ السَّائِبَ بْنَ يَزِيدَ أَخْبَرَهُ أَنَّهُ سَمِعَ سُفْيَانَ بْنَ أَبِي زُهَيْرٍ وَهُوَ رَجُلٌ مِنْ أَزْدِ شَنُوءَةَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُحَدِّثُ نَاسًا مَعَهُ عِنْدَ بَابِ الْمَسْجِدِ فَقَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اقْتَنَى كَلْبًا لَا يُغْنِي عَنْهُ زَرْعًا وَلَا ضَرْعًا نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌ قَالَ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِي وَرَبِّ هَذَا الْمَسْجِدِ","id":"Telah menceritakan kepadaku Malik dari [Yazid bin Hushaifah] bahwa [As Sa`ib bin Yazid] ia mengabarkan telah mengabarkan kepadanya, bahwa ia mendengar [Sufyan bin Abu Zuhair] -dia adalah seorang laki-laki sahabat Nabi shallallahu 'alaihi wasallam, berasal dari Azdi Syanuah, dia menceritakan hadits kepada orang-orang di depan pintu masjid- ia mengatakan \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa memelihara anjing yang tidak digunakan untuk menjaga tanaman ataupun ternak, maka akan berkurang amalnya setiap hari satu qirath.\" As Sa`ib bin Yazid bertanya; \"Apakah engkau mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?\" Dia menjawab; \"Ya, demi Rabb masjid ini.\" "},"1523":{"ar":"و حَدَّثَنِي مَالِك عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اقْتَنَى كَلْبًا إِلَّا كَلْبًا ضَارِيًا أَوْ كَلْبَ مَاشِيَةٍ نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطَانِ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memelihara anjing selain anjing yang terlatih atau anjing untuk menjaga ternak, maka akan berkurang amalannya setiap hari dua qirath.\" "},"1524":{"ar":"و حَدَّثَنِي مَالِك عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْكِلَابِ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing.\""},"1525":{"ar":"حَدَّثَنِي مَالِك عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأْسُ الْكُفْرِ نَحْوَ الْمَشْرِقِ وَالْفَخْرُ وَالْخُيَلَاءُ فِي أَهْلِ الْخَيْلِ وَالْإِبِلِ وَالْفَدَّادِينَ أَهْلِ الْوَبَرِ وَالسَّكِينَةُ فِي أَهْلِ الْغَنَمِ","id":"Telah menceritakan kepadaku Malik dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pangkal kekufuran dari arah timur, sedangkan kesombongan dan keangkuhan terdapat pada pemilik kuda dan unta. Adapun al fadad itu terdapat pada orang badui dan ketenangan terdapat pada pemilik kambing.\""},"1526":{"ar":"و حَدَّثَنِي مَالِك عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوشِكُ أَنْ يَكُونَ خَيْرَ مَالِ الْمُسْلِمِ غَنَمٌ يَتْبَعُ بِهَا شَعَفَ الْجِبَالِ وَمَوَاقِعَ الْقَطْرِ يَفِرُّ بِدِينِهِ مِنْ الْفِتَنِ","id":"Telah menceritakan kepadaku Malik dari [Abdurrahman bin Abdullah bin Abdurrahman bin Abu Sha'sha'ah] dari [Bapaknya] dari [Abu Sa'id Al Khudri] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hampir-hampir harta yang paling baik bagi seorang muslim adalah kambing; dengan kambing itu dia menyusuri puncak-pundak gunung dan tempat-tempat turunnya hujan, menyelamatkan agamanya dari berbagai fitnah.\""},"1527":{"ar":"و حَدَّثَنِي مَال��ك عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحْتَلِبَنَّ أَحَدٌ مَاشِيَةَ أَحَدٍ بِغَيْرِ إِذْنِهِ أَيُحِبُّ أَحَدُكُمْ أَنْ تُؤْتَى مَشْرُبَتُهُ فَتُكْسَرَ خِزَانَتُهُ فَيُنْتَقَلَ طَعَامُهُ وَإِنَّمَا تَخْزُنُ لَهُمْ ضُرُوعُ مَوَاشِيهِمْ أَطْعِمَاتِهِمْ فَلَا يَحْتَلِبَنَّ أَحَدٌ مَاشِيَةَ أَحَدٍ إِلَّا بِإِذْنِهِ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang memerah susu ternak orang lain tanpa izin pemiliknya. Apakah kalian suka jika kamarnya didatangi, lalu lemari penyimpanannya dihancurkan dan makanannya dipindahkan? Hanyasanya kantung susu hewan ternak itulah yang menjadi tempat penyimpanan makanan mereka, maka janganlah seseorang memerah susu ternak orang lain tanpa izinnya.\""},"1528":{"ar":"و حَدَّثَنِي مَالِك عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَكَانَ يُقَرَّبُ إِلَيْهِ عَشَاؤُهُ فَيَسْمَعُ قِرَاءَةَ الْإِمَامِ وَهُوَ فِي بَيْتِهِ فَلَا يَعْجَلُ عَنْ طَعَامِهِ حَتَّى يَقْضِيَ حَاجَتَهُ مِنْهُ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] bahwa ketika makan malam [Ibnu Umar] telah disiapkan, ia kemudian mendengar bacaan imam (shalat), sementara ia masih berada di rumahnya. Maka dia tidak mempercepat makannya sampai dia menyelesaikannya.\""},"1529":{"ar":"و حَدَّثَنِي مَالِك عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْفَأْرَةِ تَقَعُ فِي السَّمْنِ فَقَالَ انْزِعُوهَا وَمَا حَوْلَهَا فَاطْرَحُوهُ","id":"Telah menceritakan kepadaku Malik dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] dari [Abdullah bin Abbas] dari [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang tikus yang jatuh ke dalam minyak samin. Maka beliau menjawab: \"Ambillah (tikusnya), dan buanglah yang ada di sekelilingnya.\""},"1530":{"ar":"و حَدَّثَنِي مَالِك عَنْ أَبِي حَازِمِ بْنِ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ كَانَ فَفِي الْفَرَسِ وَالْمَرْأَةِ وَالْمَسْكَنِ يَعْنِي الشُّؤْمَ","id":"Telah menceritakan kepadaku Malik dari [Abu Hazim bin Dinar] dari [Sahl bin Sa'ad As Sa'idi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika memang ada, maka itu pada pada kuda, wanita, dan tempat tinggal.\" Maksudnya adalah keyakinan negatif (pesimis) ."},"1531":{"ar":"و حَدَّثَنِي مَالِك عَنْ ابْنِ شِهَابٍ عَنْ حَمْزَةَ وَسَالِمٍ ابْنَيْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشُّؤْمُ فِي الدَّارِ وَالْمَرْأَةِ وَالْفَرَسِ","id":"Telah menceritakan kepadaku Malik dari [Ibnu Syihab] dari [Hamzah] dan [Salim] anak Abdullah bin 'Umar, dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keyakinan bahwa sesuatu dapat menimbulkan kesialan ada pada tempat tinggal, wanita, dan kuda.\""},"1532":{"ar":"و حَدَّثَنِي مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّهُ قَالَجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ دَارٌ سَكَنَّاهَا وَالْعَدَدُ كَثِيرٌ وَالْمَالُ وَافِرٌ فَقَلَّ الْعَدَدُ وَذَهَبَ الْمَالُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهَا ذَمِيمَةً","id":"Telah menceritakan kepadaku Malik dari [Yahya bin Sa'id] berkata; \"Seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; 'Wahai Rasulullah, kami tinggal di sebuah rumah, jumlahnya (penghuninya) banyak, dan harta melimpah. Kemudian jumlahnya (penghuninya menjadi) berkurang dan hartapun habis, ' Rasulullah shallallahu 'alaihi wasallam bersabda: \"Biarkanlah rumah itu terhina.\""},"1533":{"ar":"حَدَّثَنِي مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلَقْحَةٍ تُحْلَبُ مَنْ يَحْلُبُ هَذِهِ فَقَامَ رَجُلٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا اسْمُكَ فَقَالَ لَهُ الرَّجُلُ مُرَّةُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْلِسْ ثُمَّ قَالَ مَنْ يَحْلُبُ هَذِهِ فَقَامَ رَجُلٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا اسْمُكَ فَقَالَ حَرْبٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْلِسْ ثُمَّ قَالَ مَنْ يَحْلُبُ هَذِهِ فَقَامَ رَجُلٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا اسْمُكَ فَقَالَ يَعِيشُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْلُبْ","id":"Telah menceritakan kepadaku Malik dari [Yahya bin Sa'id] bahwa Rasulullah shallallahu 'alaihi wasallam berkata tentang unta yang hampir melahirkan lalu diperah susunya: \"Siapa yang akan memerah susu ini?\" Lalu berdirilah seorang laki-laki, Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapa namamu?\" laki-laki itu menjawab; \"Aku Murrah.\" Rasulullah shallallahu 'alaihi wasallam berkata: \"Duduklah! \" beliau bertanya lagi: \"Siapakah yang akan memerah susu ini?\" berdirilah seorang laki-laki. Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapa namamu?\" laki-laki itu menjawab, \"Aku Harb.\" Rasulullah shallallahu 'alaihi wasallam berkata: \"Duduklah! \" beliau bertanya lagi: \"Siapakah yang akan memerah susu ini?\" lalu berdirilah seorang laki-laki. Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah namamu?\" laki-laki itu menjawab; \"Ya'isy.\" Rasulullah shallallahu 'alaihi wasallam pun kemudian berkata kepadanya: \"Perahlah! \""},"1534":{"ar":"و حَدَّثَنِي مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّ عُمَرَ بْنَ الْخَطَّابِقَالَ لِرَجُلٍ مَا اسْمُكَ فَقَالَ جَمْرَةُ فَقَالَ ابْنُ مَنْ فَقَالَ ابْنُ شِهَابٍ قَالَ مِمَّنْ قَالَ مِنْ الْحُرَقَةِ قَالَ أَيْنَ مَسْكَنُكَ قَالَ بِحَرَّةِ النَّارِ قَالَ بِأَيِّهَا قَالَ بِذَاتِ لَظًى قَالَ عُمَرُ أَدْرِكْ أَهْلَكَ فَقَدْ احْتَرَقُواقَالَ فَكَانَ كَمَا قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepadaku Malik dari [Yahya bin Sa'id] bahwa [Umar bin Khattab] bertanya kepada seorang laki-laki; \"Siapa namamu?\" Laki-laki itu menjawab, \"Jamrah.\" Umar bertanya lagi, \"Anak siapa?\" laki-laki itu menjawab, \"Anak Syihab.\" Umar bertanya lagi, \"Dari suku apa?\" laki-laki itu menjawab, \"Dari Hurqah (terbakar) \". Kemudian Umar bertanya lagi, \"Tinggal di mana?\" laki-laki itu menjawab; \"Harratin Nar (perkampungan api), \" Dia bertanya lagi, \"Di bagian mana?\" laki-laki itu menjawab, \"Di daerah Dzatu Lazha (yang memiliki nyala api) .\" Umar lalu berkata; \"Temuilah keluargamu, sesungguhnya mereka telah terbakar.\" Yahya bin Sa'id berkata, \"Maka terjadilah seperti apa yang di beritahukan Umar radliallahu 'anhu.\" "},"1535":{"ar":"حَدَّثَنِي مَالِك عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَاحْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَمَهُ أَبُو طَيْبَةَ فَأَمَرَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَاعٍ مِنْ تَمْرٍ وَأَمَرَ أَهْلَهُ أَنْ يُخَفِّفُوا عَنْهُ مِنْ خَرَاجِهِ","id":"Telah menceritakan kepadaku Malik dari [Humaid Ath Thawil] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan bekam, sementara yang membekam adalah Abu Thaibah, kemudian Rasulullah shallallahu 'alaihi wasallam memberinya satu Sha' kurma, dan menyuruh keluarganya agar meringankan beban pajaknya.\" "},"1536":{"ar":"و حَدَّثَنِي مَالِك عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ مُحَيِّصَةَ الْأَنْصَارِيِّ أَحَدِ بَنِي حَارِثَةَأَنَّهُ اسْتَأْذَنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِجَارَةِ الْحَجَّامِ فَنَهَاهُ عَنْهَا فَلَمْ يَزَلْ يَسْأَلُهُ وَيَسْتَأْذِنُهُ حَتَّى قَالَ اعْلِفْهُ نُضَّاحَكَ يَعْنِي رَقِيقَكَ","id":"Telah menceritakan kepadaku Malik dari [Ibnu Syihab] dari [Ibnu Muhaishah Al Anshari] seorang dari Bani Harisah, dia meminta izin kepada Rasulullah shallallahu 'alaihi wasallam tetang upah tukang bekam, lalu beliau melarangnya. Maka dia terus menanyakannya dan meminta izin beliau hingga beliau bersabda: \"Berikanlah pada budakmu.\""},"1537":{"ar":"حَدَّثَنِي مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشِيرُ إِلَى الْمَشْرِقِ وَيَقُولُ هَا إِنَّ الْفِتْنَةَ هَاهُنَا إِنَّ الْفِتْنَةَ هَاهُنَا مِنْ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ","id":"Telah menceritakan kepadaku Malik dari [Abdullah bin Dinar] dari [Abdullah bin Umar] berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam menunjuk ke arah timur dan bersabda: 'Sesungguhnya fitnah itu dari sana, sesungguhnya fitnah itu dari sana, dari tempat munculnya tanduk setan'.\""},"1538":{"ar":"حَدَّثَنِي مَالِك عَنْ نَافِعٍ عَنْ أَبِي لُبَابَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ قَتْلِ الْحَيَّاتِ الَّتِي فِي الْبُيُوتِ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] dari [Abu Lubabah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang membunuh ular yang ada di rumah-rumah.\""},"1539":{"ar":"و حَدَّثَنِي مَالِك عَنْ نَافِعٍ عَنْ سَائِبَةَ مَوْلَاةٍ لِعَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ قَتْلِ الْجِنَّانِ الَّتِي فِي الْبُيُوتِ إِلَّا ذَا الطُّفْيَتَيْنِ وَالْأَبْتَرَ فَإِنَّهُمَا يَخْطِفَانِ الْبَصَرَ وَيَطْرَحَانِ مَا فِي بُطُونِ النِّسَاءِ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] dari [Sa`ibah] mantan budak wanita Aisyah, bahwa Rasulullah shallallahu 'alaihi wasallam melarang membunuh sekelompok ular kecil yang ada di dalam rumah, kecuali dzu thufyatain dan al abtar, karena dua golongan ini menyilaukan mata dan dapat menggugurkan apa yang ada di kandungan. "},"1540":{"ar":"و حَدَّثَنِي مَالِك عَنْ صَيْفِيٍّ مَوْلَى ابْنِ أَفْلَحَ عَنْ أَبِي السَّائِبِ مَوْلَى هِشَامِ بْنِ زُهْرَةَ أَنَّهُ قَالَ دَخَلْتُ عَلَى أَبِي سَعِيدٍ الْخُدْرِيِّفَوَجَدْتُهُ يُصَلِّي فَجَلَسْتُ أَنْتَظِرُهُ حَتَّى قَضَى صَلَاتَهُ فَسَمِعْتُ تَحْرِيكًا تَحْتَ سَرِيرٍ فِي بَيْتِهِ فَإِذَا حَيَّةٌ فَقُمْتُ لِأَقْتُلَهَا فَأَشَارَ أَبُو سَعِيدٍ أَنْ اجْلِسْ فَلَمَّا انْصَرَفَ أَشَارَ إِلَى بَيْتٍ فِي الدَّارِ فَقَالَ أَتَرَى هَذَا الْبَيْتَ فَقُلْتُ نَعَمْ قَالَ إِنَّهُ قَدْ كَانَ فِيهِ فَتًى حَدِيثُ عَهْدٍ بِعُرْسٍ فَخَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْخَنْدَقِ فَبَيْنَا هُوَ بِهِ إِذْ أَتَاهُ الْفَتَى يَسْتَأْذِنُهُ فَقَالَ يَا رَسُولَ اللَّهِ ائْذَنْ لِي أُحْدِثُ بِأَهْلِي عَهْدًا فَأَذِنَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ خُذْ عَلَيْكَ سِلَاحَكَ فَإِنِّي أَخْشَى عَلَيْكَ بَنِي قُرَيْظَةَ فَانْطَلَقَ الْفَتَى إِلَى أَهْلِهِ فَوَجَدَ امْرَأَتَهُ قَائِمَةً بَيْنَ الْبَابَيْنِ فَأَهْوَى إِلَيْهَا بِالرُّمْحِ لِيَطْعُنَهَا وَأَدْرَكَتْهُ غَيْرَةٌ فَقَالَتْ لَا تَعْجَلْ حَتَّى تَدْخُلَ وَتَنْظُرَ مَا فِي بَيْتِكَ فَدَخَلَ فَإِذَا هُوَ بِحَيَّةٍ مُنْطَوِيَةٍ عَلَى فِرَاشِهِ فَرَكَزَ فِيهَا رُمْحَهُ ثُمَّ خَرَجَ بِهَا فَنَصَبَهُ فِي الدَّارِ فَاضْطَرَبَتْ الْحَيَّةُ فِي رَأْسِ الرُّمْحِ وَخَرَّ الْفَتَى مَيِّتًا فَمَا يُدْرَى أَيُّهُمَا كَانَ أَسْرَعَ مَوْتًا الْفَتَى أَمْ الْحَيَّةُ فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ بِالْمَدِينَ��ِ جِنًّا قَدْ أَسْلَمُوا فَإِذَا رَأَيْتُمْ مِنْهُمْ شَيْئًا فَآذِنُوهُ ثَلَاثَةَ أَيَّامٍ فَإِنْ بَدَا لَكُمْ بَعْدَ ذَلِكَ فَاقْتُلُوهُ فَإِنَّمَا هُوَ شَيْطَانٌ","id":"Telah menceritakan kepadaku Malik dari [Shaifi] mantan budak Ibnu Aflah, dari [Abu Sa`ib] mantan budak Hisyam bin Zuhrah, ia berkata; \"Aku menemui Abu Sa'id Al Khudri, tetapi saat itu ia sedang melaksanakan shalat. Aku lalu duduk menunggunya hingga dia selesai, kemudian aku mendengar ada suara dari sesuatu yang bergerak di bawah kasur di rumahnya. Ternyata itu adalah ular, lalu aku bangkit untuk membunuhnya. Abu Said mengisyaratkan agar aku tetap duduk. Ketika selesai, dia menunjukkan sebuah rumah dan bertanya; \"Apakah engkau melihat ruangan ini?\" Aku menjawab, \"Ya.\" [Abu Sa'id] lalu menuturkan, \"Dahulu ada seorang pemuda yang baru menikah, kemudian pemuda itu berangkat bersama Rasulullah shallallahu 'alaihi wasallam menuju Khandaq. Ketika dia masih bersama beliau, pemuda itu mendatangi Rasulullah shallallahu 'alaihi wasallam meminta izin. Dia berkata; \"Wahai Rasulullah, izinkan aku untuk menemui istriku karena saya baru saja menikah.\" Rasulullah shallallahu 'alaihi wasallam pun memberinya izin. Kemudian beliau bersabda kepada pemuda itu: \"Ambillah senjatamu, aku kawatir kamu dihadang Bani Quraizhah.\" Maka pulanglah pemuda itu menemui isterinya. Namun ia mendapati isterinya berada di depan pintu, hingga ia ampir saja melemparkan tombaknya kepada sang isteri karena rasa cemburu. Tapi isterinya berkata; \"Jangan terburu-buru hingga engkau masuk dan lihat apa yang terjadi di rumahmu.\" Maka dia masuk dan ternyata ada ular yang melingkar di atas kasurnya. Lalu dia tancapkan tombaknya pada ular itu dan keluar dengan membawanya dan menggantungnya di rumah. Ular itupun menggerakkan ujung tombak dan pemuda tadi tersungkur meninggal dunia. Tidak diketahui, manakah yang lebih dulu mati, pemuda itu ataukah ular tersebut. Hal itu disampaikan kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya di Madinah ada sekelompok jin yang telah masuk Islam, jika kalian melihatnya berbuat sesuatu maka izinkanlah selama tiga hari. Jika (setelah tiga hari) masih nampak maka bunuhlah karena itu adalah setan.\""},"1541":{"ar":"حَدَّثَنِي مَالِك عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرَّاكِبُ شَيْطَانٌ وَالرَّاكِبَانِ شَيْطَانَانِ وَالثَّلَاثَةُ رَكْبٌ","id":"Telah menceritakan kepadaku Malik dari [Abdurrahman bin Harmalah] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang berkendaraan sendirian adalah setan. Dua orang pengendara adalah dua setan dan tiga pengendara adalah kafilah.\""},"1542":{"ar":"و حَدَّثَنِي مَالِك عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُ كَانَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّيْطَانُ يَهُمُّ بِالْوَاحِدِ وَالْاثْنَيْنِ فَإِذَا كَانُوا ثَلَاثَةً لَمْ يَهُمَّ بِهِمْ","id":"Telah menceritakan kepadaku Malik dari [Abdurrahman bin Harmalah] dari [Sa'id bin Musayyab] berkata Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setan itu menyukai orang yang sendirian atau dua orang. Jika mereka berjumlah tiga orang, maka dia tidak menyukainya.\""},"1543":{"ar":"و حَدَّثَنِي مَالِك عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تُسَافِرُ مَسِيرَةَ يَوْمٍ وَلَيْلَةٍ إِلَّا مَعَ ذِي مَحْرَمٍ مِنْهَا","id":"Telah menceritakan kepadaku Malik dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan hari Akhir, melakukan perjalanan selama sehari semalam kecuali bersama mahramnya.\""},"1544":{"ar":"حَدَّثَنِي مَالِك عَنْ أَبِي عُبَيْدٍ مَوْلَى سُلَيْمَانَ بْنِ عَبْدِ الْمَلِكِ عَنْ خَالِدِ بْنِ مَعْدَانَ يَرْفَعُهُإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى رَفِيقٌ يُحِبُّ الرِّفْقَ وَيَرْضَى بِهِ وَيُعِينُ عَلَيْهِ مَا لَا يُعِينُ عَلَى الْعُنْفِ فَإِذَا رَكِبْتُمْ هَذِهِ الدَّوَابَّ الْعُجْمَ فَأَنْزِلُوهَا مَنَازِلَهَا فَإِنْ كَانَتْ الْأَرْضُ جَدْبَةً فَانْجُوا عَلَيْهَا بِنِقْيِهَا وَعَلَيْكُمْ بِسَيْرِ اللَّيْلِ فَإِنَّ الْأَرْضَ تُطْوَى بِاللَّيْلِ مَا لَا تُطْوَى بِالنَّهَارِ وَإِيَّاكُمْ وَالتَّعْرِيسَ عَلَى الطَّرِيقِ فَإِنَّهَا طُرُقُ الدَّوَابِّ وَمَأْوَى الْحَيَّاتِ","id":"Telah menceritakan kepadaku Malik dari [Abu 'Ubaid] mantan budak Sulaiman bin Abdul Malik, dari [Khalid bin Ma'dan] dia memarfu'kannya, Rasulullah bersabda: \"Sesungguhnya Allah Tabaraka Wa Ta'ala, Maha Lembut dan mencintai sikap lemah lembut, ridla terhadapnya dan menolong orang yang lemah lembut tidak sebagaimana Dia tidak menolong orang yang kasar. Jika engkau mengendarai tunggangan dari hewan ini, berhentikan dia di tempat-tempatnya. Jika tanahnya kering maka percepatlah jalannya selama (kendaraan tersebut) masih kuat. Hendaknya kalian berjalan di malam hari, karena tanah itu dipendekkan (jaraknya) pada malam hari, beda dengan keadaannya pada siang hari. Janganlah kalian beristirahat di tengah jalan, karena itu adalah jalannya hewan dan tempat tinggal ular.\""},"1545":{"ar":"و حَدَّثَنِي مَالِك عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّفَرُ قِطْعَةٌ مِنْ الْعَذَابِ يَمْنَعُ أَحَدَكُمْ نَوْمَهُ وَطَعَامَهُ وَشَرَابَهُ فَإِذَا قَضَى أَحَدُكُمْ نَهْمَتَهُ مِنْ وَجْهِهِ فَلْيُعَجِّلْ إِلَى أَهْلِهِ","id":"Telah menceritakan kepadaku Malik dari [Sumayya] mantan budak Abu Bakar, dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perjalanan itu bagian dari siksaan, seseorang akan terhalang tidurnya, makannya dan minum. Maka jika salah seorang di antara kalian telah menyelesaikan kebutuhan yang ada padanya, segeralah kembali kepada keluarganya.\""},"1546":{"ar":"و حَدَّثَنِي مَالِك عَنْ عَمِّهِ أَبِي سُهَيْلِ بْنِ مَالِكٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ عُثْمَانَ بْنَ عَفَّانَ وَهُوَ يَخْطُبُ وَهُوَ يَقُولُلَا تُكَلِّفُوا الْأَمَةَ غَيْرَ ذَاتِ الصَّنْعَةِ الْكَسْبَ فَإِنَّكُمْ مَتَى كَلَّفْتُمُوهَا ذَلِكَ كَسَبَتْ بِفَرْجِهَا وَلَا تُكَلِّفُوا الصَّغِيرَ الْكَسْبَ فَإِنَّهُ إِذَا لَمْ يَجِدْ سَرَقَ وَعِفُّوا إِذْ أَعَفَّكُمْ اللَّهُ وَعَلَيْكُمْ مِنْ الْمَطَاعِمِ بِمَا طَابَ مِنْهَا","id":"Telah menceritakan kepadaku Malik dari pamannya [Abu Suhail bin Malik] dari [Ayahnya] Bahwasanya ia mendengar [Utsman bin Affan] berkhutbah seraya mengatakan; \"Janganlah kalian bebani budak wanita yang tidak punya keahlian untuk bekerja, jika kalian membebaninya maka dia akan bekerja dengan kemaluannya. Janganlah kalian membebani anak kecil untuk bekerja, karena jika dia tidak mendapatkannya maka ia akan mencuri. Jagalah kehormatan, niscaya Allah akan menjaga kehormatan kalian, dan makanlah dengan makanan yang baik.\""},"1547":{"ar":"حَدَّثَنِي مَالِك عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَبْدُ إِذَا نَصَحَ لِسَيِّدِهِ وَأَحْسَنَ عِبَادَةَ اللَّهِ فَلَهُ أَجْرُهُ مَرَّتَيْنِ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang budak patuh kepada tuannya dan bagus dalam ibadah kepada Allah, maka baginya dua kali pahala.\""},"1548":{"ar":"حَدَّثَنِي مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَكُنَّا إِذَا بَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ يَقُولُ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا اسْتَطَعْتُمْ","id":"Telah menceritakan kepadaku Malik dari [Abdullah bin Dinar] bahwa [Abdullah bin Umar] berkata; \"Jika kami berbaiat kepada Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat, maka beliau akan bertitah kepada kami: 'Semampu kalian.\""},"1549":{"ar":"و حَدَّثَنِي مَالِك عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أُمَيْمَةَ بِنْتِ رُقَيْقَةَ أَنَّهَا قَالَتْأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ بَايَعْنَهُ عَلَى الْإِسْلَامِ فَقُلْنَ يَا رَسُولَ اللَّهِ نُبَايِعُكَ عَلَى أَنْ لَا نُشْرِكَ بِاللَّهِ شَيْئًا وَلَا نَسْرِقَ وَلَا نَزْنِيَ وَلَا نَقْتُلَ أَوْلَادَنَا وَلَا نَأْتِيَ بِبُهْتَانٍ نَفْتَرِيهِ بَيْنَ أَيْدِينَا وَأَرْجُلِنَا وَلَا نَعْصِيَكَ فِي مَعْرُوفٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا اسْتَطَعْتُنَّ وَأَطَقْتُنَّ قَالَتْ فَقُلْنَ اللَّهُ وَرَسُولُهُ أَرْحَمُ بِنَا مِنْ أَنْفُسِنَا هَلُمَّ نُبَايِعْكَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَا أُصَافِحُ النِّسَاءَ إِنَّمَا قَوْلِي لِمِائَةِ امْرَأَةٍ كَقَوْلِي لِامْرَأَةٍ وَاحِدَةٍ أَوْ مِثْلِ قَوْلِي لِامْرَأَةٍ وَاحِدَةٍ","id":"Telah menceritakan kepadaku Malik dari [Muhammad bin Al Munkadir] dari [Umaimah binti Ruqaiqah] berkata; \"Aku menemui Rasulullah shallallahu 'alaihi wasallam ketika para wanita membaiatnya untuk Islam. Kami mengatakan; 'Wahai Rasulullah, kami membaiat anda untuk tidak menyekutukan Allah dengan sesuatupun, tidak mencuri, tidak berzina, tidak membunuh anak-anak kami, tidak mendatangi kejahatan yang telah kami lakukan antara kedua tangan dan kaki kami, dan tidak bermaksiat terhadap anda dalam kebaikan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam menambahkan: \"Semampu dan sekuat kalian.\" Umaimah berkata, \"Kami menyahutnya, \"Allah dan Rasul-Nya lebih kami sayangi daripada diri kami. Wahai Rasulullah, kemarilah, kami akan membaiatmu.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku tidak akan bersalaman dengan wanita. Perkataanku terhadap seratus wanita adalah seperti perkataanku terhadap seorang wanita, atau seperti perkataanku untuk satu wanita.\""},"1550":{"ar":"و حَدَّثَنِي مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَكَتَبَ إِلَى عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ يُبَايِعُهُ فَكَتَبَ إِلَيْهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ أَمَّا بَعْدُ لِعَبْدِ اللَّهِ عَبْدِ الْمَلِكِ أَمِيرِ الْمُؤْمِنِينَ سَلَامٌ عَلَيْكَ فَإِنِّي أَحْمَدُ إِلَيْكَ اللَّهَ الَّذِي لَا إِلَهَ إِلَّا هُوَ وَأُقِرُّ لَكَ بِالسَّمْعِ وَالطَّاعَةِ عَلَى سُنَّةِ اللَّهِ وَسُنَّةِ رَسُولِهِ فِيمَا اسْتَطَعْتُ","id":"Telah menceritakan kepadaku Malik dari [Abdullah bin Dinar] bahwa [Abdullah bin Umar] menulis surat kepada Abdul Malik bin Marwan untuk membaiatnya, dia menulis; \"Bismillahhi arrahman arrahim; amma ba'du, untuk Abdullah, Abdul Malik Amirul mukminin, semoga kesejahteraan atasmu, aku memuji Allah untukmu, yang tidak ada ilah yang patut disembah kecuali Dia, dan aku nyatakan untuk mendengar dan taat kepadamu di atas sunnah Allah dan sunnah Rasul-Nya semampuku.\""},"1551":{"ar":"حَدَّثَنِي مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ لِأَخِيهِ كَافِرٌ فَقَدْ بَاءَ بِهَا أَحَدُهُمَا","id":"Telah menceritakan kepadaku Malik dari [Abdullah bin Dinar] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengatakan kepada saudaranya; 'Kamu kafir, ' maka (kekafirannya) akan kembali kepada salah satu di antara keduanya.\""},"1552":{"ar":"و حَدَّثَنِي مَالِك عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتَ الرَّجُلَ يَقُولُ هَلَكَ النَّاسُ فَهُوَ أَهْلَكُهُمْ","id":"Telah menceritakan kepadaku Malik dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika engkau mendengar seorang laki-laki mengatakan; 'Semoga orang-orang itu binasa' maka dialah orang yang paling binasa dari mereka.\""},"1553":{"ar":"و حَدَّثَنِي مَالِك عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقُلْ أَحَدُكُمْ يَا خَيْبَةَ الدَّهْر�� فَإِنَّ اللَّهَ هُوَ الدَّهْرُ","id":"Telah menceritakan kepadaku Malik dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang di antara kalian mengatakan; 'Betapa malangnya masa, ' karena Allah adalah masa.\""},"1554":{"ar":"و حَدَّثَنِي مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍأَنَّ عِيسَى ابْنَ مَرْيَمَ لَقِيَ خِنْزِيرًا بِالطَّرِيقِ فَقَالَ لَهُ انْفُذْ بِسَلَامٍ فَقِيلَ لَهُ تَقُولُ هَذَا لِخِنْزِيرٍ فَقَالَ عِيسَى ابْنُ مَرْيَمَ إِنِّي أَخَافُ أَنْ أُعَوِّدَ لِسَانِي الْمَنْطِقَ بِالسُّوءِ","id":"Telah menceritakan kepadaku Malik dari [Yahya bin Sa'id] berkata, \"Isa bin Maryam bertemu dengan seekor babi di suatu jalan, lalu dia berkata: \"Lewatlah dengan selamat! \" Ada yang bertanya; \"Engkau ucapkan seperti ini kepada seekor babi! \" Isa bin Maryam menjawab: \"Aku takut jika lisanku terbiasa mengucapkan kata-kata kotor.\""},"1555":{"ar":"حَدَّثَنِي مَالِك عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَلْقَمَةَ عَنْ أَبِيهِ عَنْ بِلَالِ بْنِ الْحَارِثِ الْمُزَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الرَّجُلَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ رِضْوَانِ اللَّهِ مَا كَانَ يَظُنُّ أَنْ تَبْلُغَ مَا بَلَغَتْ يَكْتُبُ اللَّهُ لَهُ بِهَا رِضْوَانَهُ إِلَى يَوْمِ يَلْقَاهُ وَإِنَّ الرَّجُلَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ سَخَطِ اللَّهِ مَا كَانَ يَظُنُّ أَنْ تَبْلُغَ مَا بَلَغَتْ يَكْتُبُ اللَّهُ لَهُ بِهَا سَخَطَهُ إِلَى يَوْمِ يَلْقَاهُ","id":"Telah menceritakan kepadaku Malik dari [Muhammad bin 'Amru bin 'Alqamah] dari [Bapaknya] dari [Bilal bin Al Haris Al Muzani] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang laki-laki mengatakan suatu kalimat yang diridlai Allah, sementara ia tidak tahu betapa besar kalimat itu, sehingga dengan kalimat itu Allah mencatat untuknya keridlaan-Nya sampai hari kiamat. Ada juga seorang laki-laki mengatakan suatu kalimat yang Allah murkai Allah, sementara ia tidak tahu betapa besar kalimat itu, sehingga Allah mencatat untuknya kemurkaan-Nya sampai hari kiamat.\""},"1556":{"ar":"و حَدَّثَنِي مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ أَنَّهُ أَخْبَرَهُ أَنَّ أَبَا هُرَيْرَةَ قَالَإِنَّ الرَّجُلَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مَا يُلْقِي لَهَا بَالًا يَهْوِي بِهَا فِي نَارِ جَهَنَّمَ وَإِنَّ الرَّجُلَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مَا يُلْقِي لَهَا بَالًا يَرْفَعُهُ اللَّهُ بِهَا فِي الْجَنَّةِ","id":"Telah menceritakan kepadaku Malik dari [Abdullah bin Dinar] dari [Abu Shalih As Samman] ia mengabarkan kepadanya, bahwa [Abu Hurairah] berkata, \"Sungguh seorang laki-laki akan mengatakan satu kalimat yang ia anggap remeh, namun justru memasukkannya ke dalam neraka Jahannam. Dan sungguh seorang laki-laki akan mengatakan satu kalimat yang ia anggap remeh, namun justru kalimat tersebut memasukkannya ke dalam surga.\""},"1557":{"ar":"حَدَّثَنِي مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَقَدِمَ رَجُلَانِ مِنْ الْمَشْرِقِ فَخَطَبَا فَعَجِبَ النَّاسُ لِبَيَانِهِمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْبَيَانِ لَسِحْرًا أَوْ قَالَ إِنَّ بَعْضَ الْبَيَانِ لَسِحْرٌ","id":"Telah menceritakan kepadaku Malik dari [Zaid bin Aslam] dari [Abdullah bin Umar] berkata; \"Dua orang datang dari timur lalu mereka menyampaikan khutbah sehingga membuat orang-orang takjub terhadap penjelasannya, Rasulullah shallallahu 'alaihi wasallam lalu bersabda: 'Sesungguhnya di antara penjelasan itu adalah sihir, ' atau beliau bersabda: 'Sesungguhnya sebagian penjelasan itu adalah sihir'.\""},"1558":{"ar":"حَدَّثَنِي مَالِك عَنْ الْوَلِيدِ بْنِ عَبْدِ اللَّهِ بْنِ صَيَّادٍ أَنَّ الْمُطَّلِبَ بْنَ عَبْدِ اللَّهِ بْنِ حَنْطَبَ الْمَخْزُومِيَّ أَخْبَرَهُأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا الْغِيبَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَذْكُرَ مِنْ الْمَرْءِ مَا يَكْرَهُ أَنْ يَسْمَعَ قَالَ يَا رَسُولَ اللَّهِ وَإِنْ كَانَ حَقًّا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قُلْتَ بَاطِلًا فَذَلِكَ الْبُهْتَانُ","id":"Telah menceritakan kepadaku Malik dari [Al Walid bin Abdullah bin Shayyad] bahwa [Al Muthallib bin Abdullah bin Hanthab Al Makhzumi] ia mengabarkan kepadanya, bahwa ada seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Apakah ghibah itu?\" Rasulullah shallallahu 'alaihi wasallam lantas menjawab: \"Engkau sebut pada diri seseorang, sesuatu yang benci jika mendengarnya.\" Laki-laki itu bertanya lagi; \"Wahai Rasulullah, walaupun yang diucapkan itu benar\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika yang engkau katakan itu hal yang batil, maka itu dusta.\""},"1559":{"ar":"حَدَّثَنِي مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ وَقَاهُ اللَّهُ شَرَّ اثْنَيْنِ وَلَجَ الْجَنَّةَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ لَا تُخْبِرْنَا فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ عَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مِثْلَ مَقَالَتِهِ الْأُولَى فَقَالَ لَهُ الرَّجُلُ لَا تُخْبِرْنَا يَا رَسُولَ اللَّهِ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ أَيْضًا فَقَالَ الرَّجُلُ لَا تُخْبِرْنَا يَا رَسُولَ اللَّهِ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ أَيْضًا ثُمَّ ذَهَبَ الرَّجُلُ يَقُولُ مِثْلَ مَقَالَتِهِ الْأُولَى فَأَسْكَتَهُ رَجُلٌ إِلَى جَنْبِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَقَاهُ اللَّهُ شَرَّ اثْنَيْنِ وَلَجَ الْجَنَّةَ مَا بَيْنَ لَحْيَيْهِ وَمَا بَيْنَ رِجْلَيْهِ مَا بَيْنَ لَحْيَيْهِ وَمَا بَيْنَ رِجْلَيْهِ مَا بَيْنَ لَحْيَيْهِ وَمَا بَيْنَ رِجْلَيْهِ","id":"Telah menceritakan kepadaku Malik dari [Zaid bin Aslam] dari [Atha bin Yasar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang Allah jaga dari dua hal, maka dia akan masuk surga.\" Lalu ada seorang laki-laki berkata; \"Wahai Rasulullah, jangan engkau beritahu kami! \" Rasulullah shallallahu 'alaihi wasallam terdiam, kemudian beliau mengatakan kembali seperti yang beliau katakan tadi. Laki-laki itu berkata; \"Jangan engkau beritahu kami, Wahai Rasulullah! \" Rasulullah shallallahu 'alaihi wasallam diam. Beliau mengulanginya lagi, kemudian laki-laki itu berkata lagi; \"Jangan engkau beritahu kami, Wahai Rasulullah! \" Rasulullah shallallahu 'alaihi wasallam mengatakannya lagi. Laki-laki itu pergi dan mengatakan seperti yang dia katakan sebelumnya, maka ada seorang laki-laki lain yang mendiamkannya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dipelihara Allah dari keburukan dua hal, niscaya dia akan masuk surga: apa yang ada di antara dua janggutnya (lisan) dan apa yang ada di antara dua kakinya. Apa yang ada di antara dua janggutnya dan apa yang ada di antara dua kakinya. Apa yang ada di antara dua janggutnya dan apa yang ada di antara dua kakinya.\""},"1560":{"ar":"و حَدَّثَنِي مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ أَنَّ عُمَرَ بْنَ الْخَطَّابِدَخَلَ عَلَى أَبِي بَكْرٍ الصِّدِّيقِ وَهُوَ يَجْبِذُ لِسَانَهُ فَقَالَ لَهُ عُمَرُ مَهْ غَفَرَ اللَّهُ لَكَ فَقَالَ أَبُو بَكْرٍ إِنَّ هَذَا أَوْرَدَنِي الْمَوَارِدَ","id":"Telah menceritakan kepadaku Malik dari [Zaid bin Aslam] dari [Ayahnya] berkata, \"Umar bin Khattab menemui [Abu Bakar As Shiddiq] sedang dia menarik lidahnya. Umar bertanya; \"Apa-apaan ini. Semoga Allah mengampunimu.\" Abu Bakar berkata; \"Sesungguhnya inilah yang mengantarku pada kebinasaan.\""},"1561":{"ar":"حَدَّثَنِي مَالِك عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ قَالَ كُنْتُ أَنَا وَعَبْدُ اللَّهِ بْنُ عُمَرَعِنْدَ دَارِ خَالِدِ بْنِ عُقْبَةَ الَّتِي بِالسُّوقِ فَجَاءَ رَجُلٌ يُرِيدُ أَنْ يُنَاجِيَهُ وَلَيْسَ مَعَ عَبْدِ اللَّهِ بْنِ عُمَرَ أَحَدٌ غَيْرِي وَغَيْرُ الرَّجُلِ الَّذِي يُرِيدُ أَنْ يُنَاجِيَهُ فَدَعَا عَبْدُ اللَّهِ بْنُ عُمَرَ رَجُلًا آخَرَ حَتَّى كُنَّا أَرْبَعَةً فَقَالَ لِي وَلِلرَّجُلِ الَّذِي دَعَاهُ اسْتَأْخِرَا شَيْئًا فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَنَاجَى اثْنَانِ دُونَ وَاحِدٍ","id":"Telah menceritakan kepadaku Malik dari [Abdullah bin Dinar] berkata; \"Aku dan [Abdullah bin Umar] berada di rumah Khalid bin 'Uqbah yang ada di pasar. Datanglah seorang laki-laki hendak berbisik dengannya, sedangkan saat itu Abdullah bin Umar tidak ada yang menemaninya kecuali aku dan pemuda yang ingin berbisik tadi. Maka Abdullah bin Umar memanggil seorang lagi sehingga kami menjadi empat orang. Lalu Abdullah bin Umar lalu berkata kepadaku dan orang yang dia panggil; 'Mudurlah sedikit, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Janganlah dua orang saling berbisik tanpa yang satunya.\""},"1562":{"ar":"و حَدَّثَنِي مَالِك عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ ثَلَاثَةٌ فَلَا يَتَنَاجَى اثْنَانِ دُونَ وَاحِدٍ","id":"Telah menceritakan kepadaku Malik dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika ada tiga orang (berkumpul), maka janganlah keduanya berbisik tanpa melibatkan yang satunya\""},"1563":{"ar":"حَدَّثَنِي مَالِك عَنْ صَفْوَانَ بْنِ سُلَيْمٍأَنَّ رَجُلًا قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْذِبُ امْرَأَتِي يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا خَيْرَ فِي الْكَذِبِ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ أَعِدُهَا وَأَقُولُ لَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا جُنَاحَ عَلَيْكَ","id":"Telah menceritakan kepadaku Malik dari [Shafwan bin Sulaim] berkata, \"Seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Aku akan berbohong kepada isteriku, Wahai Rasulullah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada kebaikan dalam berbohong\" Orang itu berkata; \"Wahai Rasulullah, aku berjanji kepadanya dan aku akan mengutarakannya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada dosa bagimu.\""},"1564":{"ar":"و حَدَّثَنِي مَالِك عَنْ صَفْوَانَ بْنِ سُلَيْمٍ أَنَّهُ قَالَقِيلَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَكُونُ الْمُؤْمِنُ جَبَانًا فَقَالَ نَعَمْ فَقِيلَ لَهُ أَيَكُونُ الْمُؤْمِنُ بَخِيلًا فَقَالَ نَعَمْ فَقِيلَ لَهُ أَيَكُونُ الْمُؤْمِنُ كَذَّابًا فَقَالَ لَا","id":"Telah menceritakan kepadaku Malik dari [Shafwan bin Sulaim] berkata; \"Ditanyakan kepada Rasulullah shallallahu 'alaihi wasallam, \"Apakah seorang mukmin bisa menjadi penakut?\" Beliau menjawab: 'Ya.\" Kemudian ditanya lagi; \"Apakah seorang mukmin bisa menjadi bakhil?\" Beliau menjawab: \"Ya.\" Lalu ditanyakan lagi; \"Apakah seorang mukmin bisa menjadi pembohong?\" Beliau menjawab: \"Tidak.\""},"1565":{"ar":"حَدَّثَنِي مَالِك عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يَرْضَى لَكُمْ ثَلَاثًا وَيَسْخَطُ لَكُمْ ثَلَاثًا يَرْضَى لَكُمْ أَنْ تَعْبُدُوهُ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَأَنْ تَعْتَصِمُوا بِحَبْلِ اللَّهِ جَمِيعًا وَأَنْ تَنَاصَحُوا مَنْ وَلَّاهُ اللَّهُ أَمْرَكُمْ وَيَسْخَطُ لَكُمْ قِيلَ وَقَالَ وَإِضَاعَةَ الْمَالِ وَكَثْرَةَ السُّؤَالِ","id":"Telah menceritakan kepadaku Malik dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah meridlai kalian karena tiga perkara dan membenci dari kalian tiga perkara. Meridhai kalian jika: kalian beribadah kepada-Nya dan tidak menyekutukan-Nya dengan sesuatupun, kalian berpegang teguh terhadap tali agama Allah secara bersama-sama dan saling menasehati terhadap orang yang Allah beri perwalian urusan kalian. Membenci kalian jika; Banyak bicara, menyia-nyiakan harta dan banyak bertanya.\""},"1566":{"ar":"و حَدَّثَنِي مَالِك عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ شَرِّ النَّاسِ ذُو الْوَجْهَيْنِ الَّذِي يَأْتِي هَؤُلَاءِ بِوَجْهٍ وَهَؤُلَاءِ بِوَجْهٍ","id":"Telah menceritakan kepadaku Malik dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia yang paling buruk adalah orang yang bermuka dua. Datang kepada sebagian orang dengan satu wajah, dan datang kepada sebagian yang lain dengan wajah yang lain.\""},"1567":{"ar":"و حَدَّثَنِي مَالِك عَنْ إِسْمَعِيلَ بْنِ أَبِي حَكِيمٍ أَنَّهُ سَمِعَ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ يَقُولُكَانَ يُقَالُ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى لَا يُعَذِّبُ الْعَامَّةَ بِذَنْبِ الْخَاصَّةِ وَلَكِنْ إِذَا عُمِلَ الْمُنْكَرُ جِهَارًا اسْتَحَقُّوا الْعُقُوبَةَ كُلُّهُمْ","id":"Telah menceritakan kepadaku Malik dari [Isma'il bin Abu Hakim] dia mendengar [Umar bin Abdul Azis] berkata: \"Dikatakan bahwa Allah Tabaraka Wa Ta'ala tidak akan menyiksa orang secara umum karena perbuatan dosa secara khusus, tetapi jika kemungkaran dilakukan terang-terangan, maka mereka semua berhak mendapatkan siksa.\""},"1568":{"ar":"حَدَّثَنِي مَالِك عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِوَخَرَجْتُ مَعَهُ حَتَّى دَخَلَ حَائِطًا فَسَمِعْتُهُ وَهُوَ يَقُولُ وَبَيْنِي وَبَيْنَهُ جِدَارٌ وَهُوَ فِي جَوْفِ الْحَائِطِ عُمَرُ بْنُ الْخَطَّابِ أَمِيرُ الْمُؤْمِنِينَ بَخٍ بَخٍ وَاللَّهِ لَتَتَّقِيَنَّ اللَّهَ أَوْ لَيُعَذِّبَنَّكَ","id":"Telah menceritakan kepadaku Malik dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] berkata; \"Saat aku keluar bersama [Umar bin Khattab Amirul Mukminin] hingga ketika sampai pada sebuah bangunan, aku mendengarnya berkata, sedangkan waktu itu antara aku dan dia terhalang tembok, dia berada di ujung bangunan, \"Bagus, bagus! Demi Allah takutlah engkau kepada Allah (hai Umar), atau Dia akan menyiksamu.\""},"1569":{"ar":"حَدَّثَنِي مَالِك عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِأَنَّهُ كَانَ إِذَا سَمِعَ الرَّعْدَ تَرَكَ الْحَدِيثَ وَقَالَ سُبْحَانَ الَّذِي يُسَبِّحُ الرَّعْدُ بِحَمْدِهِ وَالْمَلَائِكَةُ مِنْ خِيفَتِهِ ثُمَّ يَقُولُ إِنَّ هَذَا لَوَعِيدٌ لِأَهْلِ الْأَرْضِ شَدِيدٌ","id":"Telah menceritakan kepadaku Malik dari ['Amir bin Abdullah bin Zubair] bahwa jika dia mendengar suara petir, dia meninggalkan pembicaraan lalu membaca; \"SUBHANA ALLADZI YUSABBIHU RA'DU BI HAMDIHI WA AL MALAIKATU MIN KHIFATIHI.(Maha Suci Allah, Dzat yang disucikan oleh guruh dengan pujiannya dan para malaikat yang takut kepada-Nya) .\" Kemudian dia berkata; \"Sesungguhnya ini adalah peringatan keras bagi penduduk bumi.\""},"1570":{"ar":"حَدَّثَنِي مَالِك عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَدْنَ أَنْ يَبْعَثْنَ عُثْمَانَ بْنَ عَفَّانَ إِلَى أَبِي بَكْرٍ الصِّدِّيقِ فَيَسْأَلْنَهُ مِيرَاثَهُنَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ لَهُنَّ عَائِشَةُ أَلَيْسَ قَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُورَثُ مَا تَرَكْنَا فَهُوَ صَدَقَةٌ","id":"Telah menceritakan kepadaku Malik dari [Ibnu Syihab] dari ['Urwah bin Zubair] dari [Aisyah] Ummul Mukminin, bahwa isteri-isteri Nabi shallallahu 'alaihi wasallam ketika Rasulullah shallallahu 'alaihi wasallam wafat, mereka ingin mengutus Utsman bin Affan kepada Abu Bakar As Shiddiq untuk menanyakan tentang warisan mereka dari Rasulullah shallallahu 'alaihi wasallam. Maka Aisyah mengatakan kepada mereka; \"Bukankah Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Tidak diwarisi, apa yang kami tinggalkan. Apa yang kami tinggalkan adalah adalah sedekah.\""},"1571":{"ar":"و حَدَّثَنِي مَالِك عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْتَسِمُ وَرَثَتِي دَنَانِيرَ مَا تَرَكْتُ بَعْدَ نَفَقَةِ نِسَائِي وَمَئُونَةِ عَامِلِي فَهُوَ صَدَقَةٌ","id":"Telah menceritakan kepadaku Malik dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ahli warisku tidak memperoleh warisan Dinar. Apa yang telah aku tinggalkan setelah nafkah isteri-isteriku dan upah pekerjaku adalah sedekah.\""},"1572":{"ar":"حَدَّثَنِي مَالِك عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَارُ بَنِي آدَمَ الَّتِي يُوقِدُونَ جُزْءٌ مِنْ سَبْعِينَ جُزْءًا مِنْ نَارِ جَهَنَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنْ كَانَتْ لَكَافِيَةً قَالَ إِنَّهَا فُضِّلَتْ عَلَيْهَا بِتِسْعَةٍ وَسِتِّينَ جُزْءًا","id":"Telah menceritakan kepadaku Malik dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Api anak Adam yang mereka nyalakan adalah satu bagian dari tujuh puluh bagian api neraka Jahannam.\" Para sahabat bertanya, \"Wahai Rasulullah, jika itu ada, sungguh itu sudah cukup.\" Beliau menjawab: \"Sesungguhnya api neraka itu dilebihkan atasnya enam puluh sembilan bagian.\""},"1573":{"ar":"و حَدَّثَنِي مَالِك عَنْ عَمِّهِ أَبِي سُهَيْلِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَأَتُرَوْنَهَا حَمْرَاءَ كَنَارِكُمْ هَذِهِ لَهِيَ أَسْوَدُ مِنْ الْقَارِ وَالْقَارُ الزِّفْتُ","id":"Telah menceritakan kepadaku Malik dari pamannya [Abu Suhail bin Malik] dari [Bapaknya] dari [Abu Hurairah] berkata, \"Apakah kalian menyangka api Jahannam itu merah seperti api kalian ini? Sungguh api Jahannam lebih hitam daripada al qar.\" Al qar adalah ter."},"1574":{"ar":"حَدَّثَنِي مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي الْحُبَابِ سَ��ِيدِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَصَدَّقَ بِصَدَقَةٍ مِنْ كَسْبٍ طَيِّبٍ وَلَا يَقْبَلُ اللَّهُ إِلَّا طَيِّبًا كَانَ إِنَّمَا يَضَعُهَا فِي كَفِّ الرَّحْمَنِ يُرَبِّيهَا كَمَا يُرَبِّي أَحَدُكُمْ فَلُوَّهُ أَوْ فَصِيلَهُ حَتَّى تَكُونَ مِثْلَ الْجَبَلِ","id":"Telah menceritakan kepadaku Malik dari [Yahya bin Sa'id] dari [Abu Al Hubab Sa'id bin Yasar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersedekah dari usaha yang baik, dan Allah tidak menerima kecuali yang baik. Sesungguhnya dia telah meletakkannya di telapak tangan Yang Maha Pengasih. Allah akan memeliharanya sebagaimana salah seorang dari kalian memelihara anak kudanya atau anak untanya, hingga (sedekah itu) menjadi seperti gunung.\""},"1575":{"ar":"و حَدَّثَنِي مَالِك عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ مَالًا مِنْ نَخْلٍ وَكَانَ أَحَبَّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءَ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَاءٍ فِيهَا طَيِّبٍ قَالَ أَنَسٌ فَلَمَّا أُنْزِلَتْ هَذِهِ الْآيَةُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَامَ أَبُو طَلْحَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }وَإِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءَ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ شِئْتَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخْ ذَلِكَ مَالٌ رَابِحٌ ذَلِكَ مَالٌ رَابِحٌ وَقَدْ سَمِعْتُ مَا قُلْتَ فِيهِ وَإِنِّي أَرَى أَنْ تَجْعَلَهَا فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَمَهَا أَبُو طَلْحَةَ فِي أَقَارِبِهِ وَبَنِي عَمِّهِ","id":"Telah menceritakan kepadaku Malik dari [Ishaq bin Abdullah bin Abu Thalhah] Bahwasanya ia mendengar [Anas bin Malik] berkata, \"Abu Thalhah adalah orang Anshar yang paling banyak hartanya di Madinah yang berupa kurma. Adapun harta yang paling dia sukai ialah Bairuha yang berada di depan masjid. Rasulullah shallallahu 'alaihi wasallam biasa memasukinya dan minum dari airnya yang jernih.\" Anas berkata; \"Ketika ayat ini diturunkan: '(Kalian sekali-kali tidak akan mendapatkan kebaikan (yang sempurna) sehingga kalian menginfakkan sebagian harta yang kalian sukai) .' (Qs. Ali Imran: 92) Abu Thalhah berdiri menghadap Rasulullah shallallahu 'alaihi wasallam kemudian berkata; 'Wahai Rasulullah, Allah Tabaraka Wa Ta'ala berfirman: '(Kalian sekali-kali tidak akan mendapatkan kebaikan (yang sempurna) sehingga kalian menginfakkan sebagian harta yang kalian sukai) ', sungguh harta yang paling aku sukai adalah Bairuha, kebun itu saya infakkan karena Allah, aku harap kebaikannya dan penyimpanannya di sisi Allah. Wahai Rasulullah, pergunakanlah harta tersebut sebagaimana anda kehendaki.\" Anas berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hebat…! Itu adalah harta yang menguntungkan, itu adalah harta yang menguntungkan. Aku telah mendengar apa yang engkau katakan. Menurutku sebaiknya kamu memberikannya kepada karib kerabat.' Maka Abu Thalhah berkata, \"Wahai Rasulullah, akan aku lakukan.\" Kemudian dia membaginya untuk keluarga dan anak pamannya.\""},"1576":{"ar":"و حَدَّثَنِي مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعْطُوا السَّائِلَ وَإِنْ جَاءَ عَلَى فَرَسٍ","id":"Telah menceritakan kepadaku Malik dari [Zaid bin Aslam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah orang yang meminta walaupun dia datang dengan mengendarai kuda.\""},"1577":{"ar":"و حَدَّثَنِي مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَمْرِو بْنِ مُعَاذٍ الْأَشْهَلِيِّ الْأَنْصَارِيِّ عَنْ جَدَّتِهِ أَنَّهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا نِسَاءَ الْمُؤْمِنَاتِ لَا تَحْقِرَنَّ إِحْدَاكُنَّ أَنْ تُهْدِيَ لِجَارَتِهَا وَلَوْ كُرَاعَ شَاةٍ مُحْرَقًا","id":"Telah menceritakan kepadaku Malik dari [Zaid bin Aslam] dari ['Amru bin Mu'adz Al Asyhali Al Anshari] dari [Neneknya] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Wahai para wanita mukmin, janganlah salah seorang dari kalian memandang remeh untuk memberi hadiah kepada tetangganya meskipun hanya kaki kambing bakar.\""},"1578":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ نَاسًا مِنْ الْأَنْصَارِ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُمْ ثُمَّ سَأَلُوهُ فَأَعْطَاهُمْ حَتَّى نَفِدَ مَا عِنْدَهُ ثُمَّ قَالَ مَا يَكُونُ عِنْدِي مِنْ خَيْرٍ فَلَنْ أَدَّخِرَهُ عَنْكُمْ وَمَنْ يَسْتَعْفِفْ يُعِفَّهُ اللَّهُ وَمَنْ يَسْتَغْنِ يُغْنِهِ اللَّهُ وَمَنْ يَتَصَبَّرْ يُصَبِّرْهُ اللَّهُ وَمَا أُعْطِيَ أَحَدٌ عَطَاءً هُوَ خَيْرٌ وَأَوْسَعُ مِنْ الصَّبْرِ","id":"Telah menceritakan kepadaku Malik dari [Ibnu Syihab] dari ['Atha bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudri] berkata, \"Beberapa orang Anshar meminta kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memberi mereka. Kemudian mereka meminta lagi, lalu beliau memberi mereka lagi hingga semua yang beliau miliki habis. Beliau kemudian bersabda: \"Kebaikan apapun yang kumiliki, tidak akan aku simpan dari kalian. Barangsiapa yang menjaga kehormatan dirinya, niscaya Allah akan menjaga kehormatannya. Barangsiapa yang meminta kecukupan, niscaya Allah akan mencukupkannya. Barangsiapa yang berusaha sabar, niscaya Allah akan memberinya kesabaran. Tidaklah seseorang diberi pemberian yang lebih baik dan lebih luas daripada kesabaran.\""},"1579":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ عَلَى الْمِنْبَرِ وَهُوَ يَذْكُرُ الصَّدَقَةَ وَالتَّعَفُّفَ عَنْ الْمَسْأَلَةِ الْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَالْيَدُ الْعُلْيَا هِيَ الْمُنْفِقَةُ وَالسُّفْلَى هِيَ السَّائِلَةُ","id":"Telah menceritakan kepadaku dari Malik dari [Nafi'] dari [Abdullah bin Umar] berkata, \"Saat beliau di atas mimbar, beliau menyebutkan tentang sedekah dan menjaga kehormatan dari meminta-minta, beliau katakan: \"Tangan di atas lebih baik daripada tangan di bawah.\" Tangan di atas adalah orang yang memberi dan yang di bawah adalah orang yang meminta.\""},"1580":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَ إِلَى عُمَرَ بْنِ الْخَطَّابِ بِعَطَاءٍ فَرَدَّهُ عُمَرُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَ رَدَدْتَهُ فَقَالَ يَا رَسُولَ اللَّهِ أَلَيْسَ أَخْبَرْتَنَا أَنَّ خَيْرًا لِأَحَدِنَا أَنْ لَا يَأْخُذَ مِنْ أَحَدٍ شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عَنْ الْمَسْأَلَةِ فَأَمَّا مَا كَانَ مِنْ غَيْرِ مَسْأَلَةٍ فَإِنَّمَا هُوَ رِزْقٌ يَرْزُقُكَهُ اللَّهُ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ أَمَا وَالَّذِي نَفْسِي بِيَدِهِ لَا أَسْأَلُ أَحَدًا شَيْئًا وَلَا يَأْتِينِي شَيْءٌ مِنْ غَيْرِ مَسْأَلَةٍ إِلَّا أَخَذْتُهُ","id":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] dari [Atha bin Yasar] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengirim sesuatu kepada Umar bin Khattab, lalu Umar mengembalikannya. Maka Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya: \"Kenapa engkau mengembalikannya?\" Umar menjawab, \"Wahai Rasulullah, bukankah anda telah mengabarkan kepada kami bahwa kebaikan seseorang adalah tidak mengambil sesuatu dari orang lain?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maksud hal itu adalah jika dia meminta. Jika bukan dengan meminta minta, maka itu adalah rizki yang Allah berikan kepadamu.\" Umar bin Khattab berkata; \"Demi yang jiwaku berada di tangan-Nya, aku tidak akan meminta sesuatu kepada seorangpun, dan tidaklah seseorang memberiku sesuatu yang tidak aku minta kecuali aku akan mengambilnya.\""},"1581":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَنْ يَأْخُذَ أَحَدُكُمْ حَبْلَهُ فَيَحْتَطِبَ عَلَى ظَهْرِهِ خَيْرٌ لَهُ مِنْ أَنْ يَأْتِيَ رَجُلًا أَعْطَاهُ اللَّهُ مِنْ فَضْلِهِ فَيَسْأَلَهُ أَعْطَاهُ أَوْ مَنَعَهُ","id":"Telah menceritakan kepadaku Malik dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya. Sekiranya salah seorang dari kalian mengambil tali miliknya, kemudian ia mencari kayu bakar dan memanggul di atas pundaknya, maka itu lebih baik daripada mendatangi seorang laki-laki yang diberi keluasan rizki, lalu ia meminta-minta kepadanya; baik dia diberi atau ditolak.\""},"1582":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رَجُلٍ مِنْ بَنِي أَسَدٍ أَنَّهُ قَالَنَزَلْتُ أَنَا وَأَهْلِي بِبَقِيعِ الْغَرْقَدِ فَقَالَ لِي أَهْلِي اذْهَبْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْأَلْهُ لَنَا شَيْئًا نَأْكُلُهُ وَجَعَلُوا يَذْكُرُونَ مِنْ حَاجَتِهِمْ فَذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدْتُ عِنْدَهُ رَجُلًا يَسْأَلُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا أَجِدُ مَا أُعْطِيكَ فَتَوَلَّى الرَّجُلُ عَنْهُ وَهُوَ مُغْضَبٌ وَهُوَ يَقُولُ لَعَمْرِي إِنَّكَ لَتُعْطِي مَنْ شِئْتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيَغْضَبُ عَلَيَّ أَنْ لَا أَجِدَ مَا أُعْطِيهِ مَنْ سَأَلَ مِنْكُمْ وَلَهُ أُوقِيَّةٌ أَوْ عَدْلُهَا فَقَدْ سَأَلَ إِلْحَافًا قَالَ الْأَسَدِيُّ فَقُلْتُ لَلَقْحَةٌ لَنَا خَيْرٌ مِنْ أُوقِيَّةٍ قَالَ مَالِك وَالْأُوقِيَّةُ أَرْبَعُونَ دِرْهَمًا قَالَ فَرَجَعْتُ وَلَمْ أَسْأَلْهُ فَقُدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ بِشَعِيرٍ وَزَبِيبٍ فَقَسَمَ لَنَا مِنْهُ حَتَّى أَغْنَانَا اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] dari [Atha bin Yasar] dari [seorang laki-laki penduduk Bani Asad] berkata, \"Aku dan isteriku singgah di Baqi' Al Gharqad, lalu keluargaku berkata, \"Temuilah Rasulullah shallallahu 'alaihi wasallam, lalu mintalah sesuatu yang bisa kita makan.\" Mereka lalu menyebutkan kebutuhannya masing-masing, kemudian aku pergi menemui Rasulullah shallallahu 'alaihi wasallam, aku mendapati seseorang sedang meminta sesuatu kepada beliau. Rasulullah shallallahu 'alaihi wasallam menjawab: \"Aku sudah tidak mempunyai apa yang bisa kuberikan untukmu.\" Orang itu pergi dengan marah seraya mengatakan, \"Sungguh, engkau bisa memberi siapa saja yang engkau kehendaki! \" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia marah kepadaku, karena aku tidak mempunyai apa yang dia minta. Barangsiapa di antara kalian yang meminta padahal dia mempunyai satu uqiyyah atau senilai itu, sungguh dia telah meminta sesuatu dengan cara paksa.\" Al Asadi berkata; \"Unta kami yang hampir melahirkan lebih baik daripada satu 'uqiyah.\" Malik berkata; \"Satu 'uqiyah adalah empat puluh dirham.\" Laki-laki dari Bani As'ad lalu berkata, \"Aku kembali tanpa memintanya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam diberi seseorang tepung dan gandum, lalu beliau membagi untuk kami hingga Allah Azza Wa Jalla mencukupkan kami.\""},"1583":{"ar":"و عَنْ مَالِك عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَهُ يَقُولُمَا نَقَصَتْ صَدَقَةٌ مِنْ مَالٍ وَمَا زَادَ اللَّهُ عَبْدًا بِعَفْوٍ إِلَّا عِزًّا وَمَا تَوَاضَعَ عَبْدٌ إِلَّا رَفَعَهُ اللَّهُقَالَ مَالِك لَا أَدْر��ي أَيُرْفَعُ هَذَا الْحَدِيثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْ لَا","id":"Dari Malik dari [Al 'Ala` bin Abdurrahman] Bahwasanya ia mendengar dia berkata, \"Harta tidak akan berkurang karena sedekah, dan Allah tidak menambah seorang hamba yang pemaaf kecuali kemuliaan. Dan tidaklah seorang hamba itu bertawadhu' kecuali Allah mengangkat derajatnya.\" Malik berkata; \"Aku tidak tahu apakah hadits ini marfu' kepada Nabi shallallahu 'alaihi wasallam atau tidak.\""},"1584":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ رَجُلًا مِنْ بَنِي عَبْدِ الْأَشْهَلِ عَلَى الصَّدَقَةِ فَلَمَّا قَدِمَ سَأَلَهُ إِبِلًا مِنْ الصَّدَقَةِ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى عُرِفَ الْغَضَبُ فِي وَجْهِهِ وَكَانَ مِمَّا يُعْرَفُ بِهِ الْغَضَبُ فِي وَجْهِهِ أَنْ تَحْمَرَّ عَيْنَاهُ ثُمَّ قَالَ إِنَّ الرَّجُلَ لَيَسْأَلُنِي مَا لَا يَصْلُحُ لِي وَلَا لَهُ فَإِنْ مَنَعْتُهُ كَرِهْتُ الْمَنْعَ وَإِنْ أَعْطَيْتُهُ أَعْطَيْتُهُ مَا لَا يَصْلُحُ لِي وَلَا لَهُ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ لَا أَسْأَلُكَ مِنْهَا شَيْئًا أَبَدًا","id":"Telah menceritakan kepadaku dari Malik dari [Abdullah bin Abu Bakar] dari [Ayahnya] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengangkat seorang laki-laki dari Bani Abdul Al Asyhal sebagai 'amil zakat. Ketika beliau tiba, laki-laki itu meminta seekor unta dari zakat tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam marah, hingga kemarahan itu nampak pada wajahnya. Di antara tanda kemarahan beliau adalah kedua matanya memerah. Kemudian beliau bersabda: \"Sesungguhnya ada seorang laki-laki memintaku, sesuatu yang tidak pantas untukku dan juga untuknya. Jika aku menolaknya, sungguh aku tidak suka menolak (untuk memberi) . Jika aku memberinya, berarti aku memberikan sesuatu yang tidak pantas untuk aku terima dan tidak pula dia terima.\" Lalu orang itu berkata; \"Wahai Rasulullah, aku tidak akan meminta sesuatupun darimu selamanya.\""},"1585":{"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ أَنَّهُ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ الْأَرْقَمِادْلُلْنِي عَلَى بَعِيرٍ مِنْ الْمَطَايَا أَسْتَحْمِلُ عَلَيْهِ أَمِيرَ الْمُؤْمِنِينَ فَقُلْتُ نَعَمْ جَمَلًا مِنْ الصَّدَقَةِ فَقَالَ عَبْدُ اللَّهِ بْنُ الْأَرْقَمِ أَتُحِبُّ أَنَّ رَجُلًا بَادِنًا فِي يَوْمٍ حَارٍّ غَسَلَ لَكَ مَا تَحْتَ إِزَارِهِ وَرُفْغَيْهِ ثُمَّ أَعْطَاكَهُ فَشَرِبْتَهُ قَالَ فَغَضِبْتُ وَقُلْتُ يَغْفِرُ اللَّهُ لَكَ أَتَقُولُ لِي مِثْلَ هَذَا فَقَالَ عَبْدُ اللَّهِ بْنُ الْأَرْقَمِ إِنَّمَا الصَّدَقَةُ أَوْسَاخُ النَّاسِ يَغْسِلُونَهَا عَنْهُمْ","id":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] dari [Ayahnya] berkata; [Abdurrahman bin Al Arqam] berkata, \"Tunjukkan kepadaku seekor unta tunggangan yang bisa aku gunakan untuk membawa Amirul mukminin.\" Aku lalu berkata, \"Ya. ada seekor unta jantan dari unta sedekah.\" Lalu Abdullah bin Al Arqam bertanya, \"Apakah kamu senang jika ada seorang laki-laki gemuk pada suatu siang yang sangat panas, mencuci apa yang ada di bawah sarungnya dan pangkal pahanya karenamu. Lalu dia memberikan (airnya) kepadamu dan engkau meminumnya?\" Aslam berkata, \"Aku pun marah, lalu kukatakan, \"Semoga Allah mengampunimu, kenapa engkau mengatakan seperti ini kepadaku?\" Abdullah bin Arqam berkata; \"Sesungguhnya zakat adalah kotoran manusia yang mereka bersihkan dari diri mereka.\""},"1586":{"ar":"حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ أَنَّ عُمَرَ بْنَ الْخَطَّابِاسْتَعْمَلَ مَوْلًى لَهُ يُدْعَى هُنَيًّا عَلَى الْحِمَى فَقَالَ يَا هُنَيُّ اضْمُمْ جَنَاحَكَ عَنْ النَّاسِ وَاتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّ دَعْوَةَ الْمَظْلُومِ مُجَابَةٌ وَأَدْخِلْ رَبَّ الصُّرَيْمَةِ وَرَبَّ الْغُنَيْمَةِ وَإِيَّايَ وَنَعَمَ ابْنِ عَفَّانَ وَابْنِ عَوْفٍ فَإِنَّهُمَا إِنْ تَهْلِكْ مَاشِيَتُهُمَا يَرْجِعَانِ إِلَى الْمَدِينَةِ إِلَى زَرْعٍ وَنَخْلٍ وَإِنَّ رَبَّ الصُّرَيْمَةِ وَالْغُنَيْمَةِ إِنْ تَهْلِكْ مَاشِيَتُهُ يَأْتِنِي بِبَنِيهِ فَيَقُولُ يَا أَمِيرَ الْمُؤْمِنِينَ يَا أَمِيرَ الْمُؤْمِنِينَ أَفَتَارِكُهُمْ أَنَا لَا أَبَا لَكَ فَالْمَاءُ وَالْكَلَأُ أَيْسَرُ عَلَيَّ مِنْ الذَّهَبِ وَالْوَرِقِ وَايْمُ اللَّهِ إِنَّهُمْ لَيَرَوْنَ أَنِّي قَدْ ظَلَمْتُهُمْ إِنَّهَا لَبِلَادُهُمْ وَمِيَاهُهُمْ قَاتَلُوا عَلَيْهَا فِي الْجَاهِلِيَّةِ وَأَسْلَمُوا عَلَيْهَا فِي الْإِسْلَامِ وَالَّذِي نَفْسِي بِيَدِهِ لَوْلَا الْمَالُ الَّذِي أَحْمِلُ عَلَيْهِ فِي سَبِيلِ اللَّهِ مَا حَمَيْتُ عَلَيْهِمْ مِنْ بِلَادِهِمْ شِبْرًا","id":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] dari [Ayahnya] bahwa [Umar bin Khattab] memperkerjakan mantan budaknya yang bernama Hunayya untuk menjaga perbatasan. Lalu 'Umar berkata; \"Wahai Hunayya! Tahanlah tanganmu dari berbuat aniaya terhadap manusia dan takutlah doa orang-orang yang teraniaya. Karena doa orang-orang yang teraniaya itu dikabulkan. Masukkan pemilik unta dan kambing yang sedikit. Biarkan ternak Ibnu Affan dan Ibnu 'Auf, jika kedua ternak mereka habis, mereka akan kembali ke Madinah untuk bertani dan bercocok tanam. Penggembala yang memiliki unta atau kambing yang sedikit, jika telah habis ternaknya, mereka akan mendatangiku membawa anaknya seraya mengatakan 'Wahai Amirul Mu'minin! wahai Amirul Mu'minin! apakah engkau akan meninggalkan mereka? Aku tidaklah enggan denganmu, air dan rumput lebih ringan bagiku daripada emas dan perak. Demi Allah, mereka melihat bahwa aku telah menganiaya mereka. Ini adalah tanah mereka dan air mereka. Mereka berjuang untuk mendapatkannya pada masa Jahiliyah dan menyerahkannya pada masa Islam. Demi Dzat yang jiwaku di tangan-Nya, jika bukan karena harta yang aku bawa di jalan Allah, aku tidak akan menjaga tanah mereka sejengkalpun'.\""},"1587":{"ar":"حَدَّثَنِي مَالِك عَنْ ابْنِ شِهَابٍ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِي خَمْسَةُ أَسْمَاءٍ أَنَا مُحَمَّدٌ وَأَنَا أَحْمَدُ وَأَنَا الْمَاحِي الَّذِي يَمْحُو اللَّهُ بِيَ الْكُفْرَ وَأَنَا الْحَاشِرُ الَّذِي يُحْشَرُ النَّاسُ عَلَى قَدَمِي وَأَنَا الْعَاقِبُ","id":"Telah menceritakan kepadaku Malik dari [Ibnu Syihab] dari [Muhammad bin Jabir bin Muth'im] bahwa Nabi shallallahu 'alaihi wasallam berkata kepadaku: \"Aku mempunyai lima nama: Aku adalah Muhammad, Ahmad, Al Mahi yang mana Allah telah menghapuskan kekufuran denganku, Al Haasyir, yang mana seluruh manusia dikumpulkan pada telapak kakiku, dan Al 'Aqib.\""}};
